-- ── Lessons: Welcome to IAT ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Welcome Message from Kacy', 'welcome-message-from-kacy', '<h2>Welcome Message from Kacy</h2><p><strong>Message from Kacy, President of Innovative Air Technologies:</strong></p><p>Welcome to the Innovative Air Technologies team! I am thrilled to have you on board and look forward to working alongside you. Our company values each and every employee, and we are committed to providing a positive and enjoyable workplace environment where everyone can thrive and succeed. You were hired because we see the unique value and potential you bring to our team, and we believe that by working together, we can achieve great things.</p><p>At Innovative Air Technologies, we view our employees as an integral part of our success and growth. We want you to know that we are dedicated to your professional development and well-being, and we are excited to have you as a part of our team indefinitely. Your contributions are highly valued, and we encourage you to share your ideas, insights, and feedback as we work together towards our common goals. Together, we can create a workplace where everyone feels empowered, supported, and appreciated.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Photo of Kacy Orr, President of Innovative Air Technologies — re-upload via admin editor</figcaption></figure>', 0, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our History', 'our-history', '<h2>Our History</h2><p>Since the inception of Innovative Air Technologies in 2001, we&apos;ve desired to change the status quo in low humidity systems.</p><p>We utilize state-of-the-art technology and our 50+ years of experience has solved some of the world&apos;s most complex moisture and temperature control challenges.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Where we come from...&quot; embedded YouTube video about IAT history — re-upload via admin editor</figcaption></figure>', 1, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Vision', 'our-vision', '<h2>Our Vision</h2><p>Our vision is to enrich the lives of our customers by offering quality, flexible, value-driven dry air solutions by utilizing our expert knowledge in the field of psychrometrics and desiccant dehumidification.</p><p>We innovate with each of our dehumidification products and offer industry-leading customer service experience from planning to implementation and beyond.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Small Company, BIG Results&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure>', 2, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Goal', 'our-goal', '<h2>Our Goal</h2><p>IAT exists to resolve our customer&apos;s humidity issues in many various applications.</p><p>We attain high personal integrity, and exceptional product quality while having fun doing what we do.</p><p>We will succeed by having an excellent cohesive team that yields exceptional, innovative industrial desiccant dehumidifiers with outstanding customer service.</p>', 3, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Meet the Team', 'meet-the-team', '<h2>Meet the Team</h2><h3>Kacy Orr, President</h3><figure class="img-missing"><figcaption>📷 Image from Trainual: Photo of Kacy Orr — re-upload via admin editor</figcaption></figure><p><strong>The Official Bio:</strong></p><p>Kacy, a forward-thinking visionary, plays a pivotal role in shaping the strategic direction of Innovative Air Technologies. While he actively oversees all facets of company operations, Kacy&apos;s primary areas of passion and expertise lie within the realms of sales and engineering. His main objective revolves around ensuring that IAT is equipped to offer customers the valuable resources required for resolving their humidity-related challenges, while also nurturing customer relationships that will endure for years to come.</p><p>Kacy&apos;s journey in the humidity control industry has deep roots. His extensive experience and affinity for desiccant dehumidification are found in his upbringing and professional history.</p><p>Before founding Innovative Air Technologies in 2001, Kacy dedicated his full-time efforts to Low Humidity Systems, a company owned by his father, Jerry, since 1981. Raised within the industry of desiccant dehumidification, Kacy brings a wealth of industry knowledge and a commitment to excellence that underscores his leadership within the organization.</p><p><strong>Stuff we leave out of the official bio:</strong></p><ul><li>He has 4 dogs.</li><li>He loves soccer &amp; golf.</li></ul><h3>Crystal Hill, Director of Operations</h3><p><strong>The Official Bio:</strong></p><p>Crystal has been an integral part of the Innovative Air Technologies team since its inception in 2001. Prior to joining IAT, she had the privilege of working alongside Jerry at Low Humidity Systems, further enriching her industry experience.</p><p>With over 20 years of combined expertise in customer service and comprehensive office functions, Crystal brings a wealth of knowledge and dedication to her role. She excels as a proficient multitasker, ensuring the successful execution of responsibilities. Crystal&apos;s unwavering commitment to excellence is evident in every aspect of her work.</p><p><strong>What&apos;s not in the official bio:</strong></p><p>Next to Kacy, Crystal is the knower of all the things.</p><h3>James Pope, Director of Engineering &amp; Production</h3><p><strong>The Official Bio:</strong></p><p>James, hailing from the East Coast of Canada, holds degrees in Civil Engineering from both New Brunswick Community College and Old Dominion University. James began his professional journey with a strong foundation in engineering principles. In 2010, he relocated to the United States alongside his family, marking a significant juncture in his career.</p><p>James&apos; fascination with engineering traces back to his formative years, where he enthusiastically engaged in electronic projects alongside his grandfather. This early exposure kindled a lifelong passion for design and innovation, a fervor that has only intensified over the course of his 20-year career in engineering.</p><p>James joined the Innovative Air Technologies team in 2015, assuming the role of Design Engineer. His exemplary dedication, proficiency, and unwavering commitment to excellence swiftly propelled him into the position of Engineering Manager.</p><p><strong>What the official bio didn&apos;t tell you:</strong></p><p>If you can&apos;t find him, he&apos;s probably in the breakroom making coffee.</p><h3>David Schurk, National Sales Manager</h3><p><strong>The Official Bio:</strong></p><p>David, holding credentials as DES, CEM, LEED-AP, COS, WEP 57, CIAQ, is National Sales Manager for Innovative Air Technologies in Covington, GA. He also serves as an ASHRAE Distinguished Lecturer and ASHRAE Life Member, and Committee Chair for the ASHRAE Sustainability and Decarbonization Leadership Task Force. He has over 40 years of experience in the design and analysis of heating, ventilating, and air-conditioning systems for a variety of market sectors, with special focus on healthcare and aerospace environmental control and air quality.</p><p><strong>You won&apos;t see this in the official bio:</strong></p><ul><li>He starts every morning (when at home) in a coffee shop — if he can find one open as early as he wakes up.</li><li>He loves spending time with his 5 grandchildren.</li></ul><h3>Jerry Orr, Humidity Consultant</h3><p><strong>The Official Bio:</strong></p><p>For those seeking a wealth of seasoned expertise, Jerry stands as an exemplary figure. With an unparalleled legacy spanning over five decades in the industry of desiccant dehumidification and humidity control, Jerry&apos;s unique career is a testament to his unwavering commitment to the field.</p><p>From 1951 to 2001, Jerry owned and operated Low Humidity Systems, a period during which he cemented his reputation as a pioneer and authority in the dehumidification industry. In 2001, he opted for semi-retirement, choosing to continue his journey by joining Innovative Air Technologies as an expert humidity consultant.</p><p>Jerry&apos;s exceptional career is complemented by his dedicated service to the United States Air Force from 1953 to 1963. His experience and enduring dedication are invaluable assets to Innovative Air Technologies, representing a legacy that continues to shape the humidity control industry to this day.</p><p><strong>Not in the bio:</strong></p><p>Jerry is the humidity Yoda. &ldquo;Always Other Possibilities.&rdquo;</p><h3>Summer Neal, Marketing Manager</h3><p><strong>The Official Bio:</strong></p><p>Summer Neal is a versatile professional with a diverse background spanning healthcare, marketing, and communications. After 22 years as a dental hygienist, Summer transitioned her career path to pursue her passion for marketing by obtaining a Bachelor of Science in Strategic Communications from Liberty University (2022).</p><p>In addition to her role as Marketing Manager at Innovative Air Technologies, Summer volunteers as Communications Director for her local church, and serves as the Social Media Manager for the Mayor of Porterdale, GA.</p><p><strong>What&apos;s not in the official bio:</strong></p><p>Coffee is her love language — she doesn&apos;t interact with people in the morning until after coffee. She also sings, plays piano, and loves Superman!</p>', 4, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Core Values', 'core-values', '<h2>Core Values</h2><h3>Why Our Core Values Matter</h3><p>Why our core values matter is a fundamental question that lies at the heart of Innovative Air Technologies. Our core values serve as the guiding principles that shape our company culture and define who we are as an organization. These values are not just words on a wall; they are the driving force behind every decision we make and every action we take. They provide us with a clear sense of direction and purpose, helping us stay focused on our mission and goals.</p><p>At Innovative Air Technologies, we believe that our core values are more than just a set of ideals &mdash; they are the foundation of our success. We understand that the people we bring into our organization must embody and uphold these principles. By aligning our team with our core values, we create a cohesive and high-performing work environment where everyone is working towards a common goal.</p><p>Our core values are not just something we talk about; they are at the center of everything we do. From how we interact with our customers and vendors to how we collaborate with our colleagues, our core values are the lens through which we view the world. They shape our decisions, guide our behavior, and ultimately define the reputation of our company.</p><ol><li>Solve Problems</li><li>Golden Rule Mentality</li><li>Quality Matters</li><li>Have Fun</li><li>Colossians 3:23</li><li>Integrity is Key</li><li>Clean is King</li><li>Innovative Thinking</li><li>We Are A Team</li></ol><hr><h3>1. Solve Problems</h3><p>Core values are the guiding principles that dictate behavior and action within a company. For Innovative Air Technologies, one of our core values is <strong>&ldquo;Solve Problems.&rdquo;</strong> This value reflects the company&apos;s commitment to addressing challenges and finding solutions. By focusing on problem-solving, the company aims to not only meet but exceed customer expectations and workplace needs.</p><p>This core value is deeply ingrained in the company&apos;s mission and culture. We exist to solve our customer&apos;s problems and enrich the lives of others. This others-centric approach sets us apart as a service-oriented organization that happens to specialize in building dehumidifiers. By prioritizing problem-solving, our company demonstrates a commitment to delivering effective solutions and exceptional customer service.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Problem Solving DNA&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>2. Golden Rule Mentality</h3><p><strong>Golden Rule Mentality</strong> is a core value that lies at the heart of Innovative Air Technologies. This principle dictates that individuals should treat others, including their colleagues and customers, in the same way they would want to be treated themselves. By embodying the Golden Rule Mentality, employees at Innovative Air Technologies strive to create a positive and respectful work environment where everyone feels valued and appreciated.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Golden Rule Mentality&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>3. Quality Matters</h3><p>Quality is at the core of everything we do at Innovative Air Technologies. Our commitment to excellence is reflected in our core value that <strong>quality matters</strong> above all else. We believe that if our equipment doesn&apos;t perform as expected, then we are not just failing to meet expectations, but we are also creating new problems for our customers. This dedication to quality ensures that every product we deliver is reliable, efficient, and meets the highest standards in the industry.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Quality Matters&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>4. Have Fun</h3><p>Our core value of <strong>Have Fun</strong> means that the company believes that work doesn&apos;t have to feel like a chore, and employees should enjoy what they do on a daily basis.</p><p>Having fun as a core value can have numerous benefits for both employees and the company as a whole. When employees enjoy their work they are more engaged, motivated, and productive. A positive and fun work environment can also lead to increased creativity, collaboration, and job satisfaction. It can help foster a sense of camaraderie among team members and create a supportive and inclusive culture.</p><p>At Innovative Air Technologies, embracing the core value of having fun can be reflected in various ways within the organization. This could include organizing team-building activities, celebrating achievements and milestones, promoting a healthy work-life balance, and encouraging a positive attitude towards work. By prioritizing fun as a core value, the company can create a workplace where employees feel valued, motivated, and happy to come to work each day.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Have Fun&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>5. Colossians 3:23</h3><p><strong>Colossians 3:23</strong> guides our work ethic and company culture. This verse emphasizes the importance of working diligently and wholeheartedly, as if working for the Lord himself. By embodying this principle, the employees at Innovative Air Technologies are motivated to give their best effort in all tasks and endeavors.</p><p>At Innovative Air Technologies, the core value of Colossians 3:23 is more than just a motto &mdash; it is a way of life. Employees are encouraged to work hard and play hard, all while keeping their focus on serving a higher purpose. This mindset creates a positive and productive work environment where individuals are inspired to excel in their roles and contribute to the company&apos;s success.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Colossians 3:23&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>6. Integrity is Key</h3><p>Integrity is not just a principle but a practice that permeates every layer of our organization. This commitment to integrity ensures that we consistently act in the best interest of not only our stakeholders but also the communities we serve. We believe that by maintaining a steadfast dedication to these values, we create a positive, trust-filled environment that benefits everyone involved.</p><p>In our pursuit of excellence, we recognize that integrity is the foundation upon which lasting relationships are built. Whether it&apos;s dealing with our customers, collaborating with partners, or interacting within our teams, we strive to be transparent and honest in all our communications. This approach fosters an atmosphere of mutual respect and understanding, which is essential for achieving our collective and individual goals.</p><p>We also understand that upholding high standards of integrity requires constant vigilance and a proactive approach to ethical challenges. As such, we are committed to providing continuous education and training for our employees, ensuring they are equipped to make decisions that align with our core values.</p><p>Ultimately, our unwavering commitment to integrity is what sets us apart. It&apos;s the cornerstone of our reputation and the key to our long-term success. We pledge to continue upholding these principles, as we believe they are essential to creating sustainable value for all our stakeholders and for society as a whole.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Integrity Matters&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>7. Clean is King</h3><p>The core value of <strong>&ldquo;Clean is King&rdquo;</strong> is a foundational belief that influences every aspect of our business operations. This core value emphasizes the importance of cleanliness in all areas of the company, from the employee workspace to the products and services we provide.</p><p>At Innovative Air Technologies, the mantra that &ldquo;a clean workspace is an efficient workspace&rdquo; is deeply ingrained in our company culture. We understand that a clean and organized work environment not only promotes employee well-being and productivity but also reflects positively on the company&apos;s image and reputation. By prioritizing cleanliness, we are able to create a professional and welcoming atmosphere for everyone.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Clean is KING!&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><p>While we&apos;re talking about being clean, let&apos;s watch a short video about proper handwashing.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;IAT LEAN: Handwashing with Kacy&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure><hr><h3>8. Innovative Thinking</h3><p>Innovative Air Technologies prides itself on our ability to utilize <strong>innovative thinking</strong>. This fundamental principle drives the company&apos;s approach to problem-solving, product development, and overall business strategy. By fostering a culture of creativity and forward-thinking, we are able to stay ahead of the curve in a constantly evolving industry.</p><p>Our commitment to innovative thinking is more than just a catch-phrase &mdash; it is a guiding philosophy that influences every aspect of our organization. From the design of cutting-edge air dehumidification systems to the implementation of groundbreaking technologies, we encourage our team members to think outside the box and explore new possibilities.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;Questions we always ask at IAT&quot; graphic about innovative thinking — re-upload via admin editor</figcaption></figure><hr><h3>9. We Are A Team</h3><p>At Innovative Air Technologies, the core value of <strong>&ldquo;We Are A Team&rdquo;</strong> is at the heart of everything we do. This value emphasizes the importance of collaboration, unity, and mutual support among all team members.</p><p>When it comes to teamwork, the motto &ldquo;we win together, we lose together&rdquo; encapsulates the spirit of unity and shared responsibility within the company. Team members at Innovative Air Technologies understand that success is a collective effort and that challenges are best overcome through collaboration and cooperation.</p><p>By working together as a team, employees at Innovative Air Technologies are able to accomplish remarkable things that would be impossible to achieve alone. The synergy created by individuals coming together with a shared purpose and a commitment to each other&apos;s success enables the company to thrive and achieve its goals.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: &quot;We Are A Team&quot; embedded YouTube video — re-upload via admin editor</figcaption></figure>', 5, TRUE, 8
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'welcome-to-iat'
ON CONFLICT (module_id, slug) DO NOTHING;

-- ── Lessons: New Rep Onboarding ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Welcome', 'welcome', '<h2>Welcome</h2><p>It is my pleasure to welcome you as you embark on your journey with Innovative Air Technologies. I am delighted to have you join our dynamic team of professionals.</p><p>At Innovative Air Technologies, we pride ourselves on being leaders in the field of industrial desiccant dehumidifiers. Our commitment to excellence, innovation, and enriching the lives of our customers has given us a competitive advantage in the industry. As a Sales Representative, you play a vital role in our continued success and growth.</p><p>In this Sales Representative Onboarding Manual, you will find valuable insights, resources, and tools to equip you for success in your role. From understanding our product line to mastering sales techniques, we are dedicated to providing you with the support and guidance you need to thrive in your position.</p><p>Our company culture is built on our core values and as you become part of the Innovative Air Technologies family, you will discover a supportive and collaborative environment where your contributions are valued and recognized.</p><p>I encourage you to embrace this opportunity with enthusiasm and determination. Together, we will achieve great things and continue to exceed the expectations of our customers.</p><p>Once again, welcome to Innovative Air Technologies. I look forward to witnessing your growth and success with us.</p><p>Warm regards,<br><strong>Kacy</strong></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Kacy welcome video embed — re-upload via admin editor</figcaption></figure>', 0, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Meet the Team', 'meet-the-team', '<h2>Meet the Team</h2><h3>Kacy Orr, President</h3><p>Meet Kacy, the driving force behind Innovative Air Technologies. With a keen eye for the future, he meticulously crafts our strategic vision. Passionate about sales and engineering, Kacy ensures that IAT delivers comprehensive solutions to our customers'' humidity challenges, fostering enduring relationships. His journey began at Low Humidity Systems under his father''s guidance before founding Innovative Air Technologies in 2001.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Video — Meet Kacy Orr, President of Innovative Air Technologies — re-upload via admin editor</figcaption></figure><h3>David Schurk, National Sales Manager</h3><p>DEE, CEM, LEED-AP, CGNA, CWEP, SFP, CIAQM. David is National Sales Manager for Innovative Air Technologies in Covington, GA. He also serves as an ASHRAE Distinguished Lecturer, is an ASHRAE Life Member, and Committee Chair for the ASHE Sustainability and Decarbonization Leadership Task Force. He has over 40 years of experience in the design and analysis of heating, ventilating, and air-conditioning systems for a variety of market sectors, with a special focus on healthcare and aerospace environmental control and air quality.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Video — Meet David Schurk — re-upload via admin editor</figcaption></figure><h3>Crystal Hill, Director of Operations</h3><p>Crystal has been with Innovative Air Technologies since its inception in 2001. She began her career working for Low Humidity Systems. She has 22+ years combined in customer service and all areas of office functions. She is an excellent multi-tasker and works hard to ensure all tasks are successfully completed.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Video — Crystal Hill, Director of Operations — re-upload via admin editor</figcaption></figure><h3>James Pope, Director of Engineering &amp; Production</h3><p>James grew up on the East Coast of Canada and holds degrees in Civil Engineering from New Brunswick Community College &amp; Old Dominion University. James moved to the US with his family in 2010. His love for engineering started at a young age as he completed electronic projects with his grandfather. After 20 years of engineering experience, his passion to design and create continues to grow.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Video — Meet James Pope, Director of Engineering &amp; Production — re-upload via admin editor</figcaption></figure><h3>Summer Neal, Marketing Manager</h3><p>Summer is a versatile professional with a diverse background. After 22 years as a dental hygienist, she transitioned her career to pursue her passion for marketing by obtaining a BS in Strategic Communications from Liberty University (2022). Summer oversees Innovative Air Technologies marketing efforts, including branding, website, digital and print media and social media.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Video — Meet Summer, your friendly neighborhood Marketing Manager — re-upload via admin editor</figcaption></figure><h3>Jerry Orr, Humidity Consultant</h3><p>If you are ever looking for someone who has experienced it all, look no further than Jerry. He has over 50 years of experience in the desiccant dehumidification and humidity control field. Jerry owned and operated Low Humidity Systems from 1981–2001 when he decided to semi-retire and come to work for IAT as a humidity consultant.</p>', 1, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Overview & Core Values', 'company-overview-and-core-values', '<h2>Company Overview &amp; Core Values</h2><h3>Our History</h3><p>Since the inception of Innovative Air Technologies in 2001, we''ve desired to change the status quo in low humidity systems. We utilize state-of-the-art technology and our 50+ years of experience has solved some of the world''s most complex moisture and temperature control challenges.</p><h3>Our Vision</h3><p>Our vision is to enrich the lives of our customers by offering quality, flexible, value-driven dry air solutions by utilizing our expert knowledge in the field of Psychrometrics and desiccant dehumidification. We innovate with each of our dehumidification products and offer our industry-leading customer service experience from planning to implementation and beyond.</p><h3>Our Goal</h3><p>IAT exists to resolve our customer''s humidity issues in many various applications. We attain high personal integrity, and exceptional product quality while having fun doing what we do. We will succeed by having an excellent team that has always been exceptional, innovative industrial desiccant dehumidifiers with outstanding customer service.</p><h3>Core Values</h3><ol><li><strong>Solve Problems</strong> — We exist to solve our customer''s problems and enrich the lives of others. We are a customer service company, we just happen to build dehumidifiers.</li><li><strong>Quality Matters</strong> — If our equipment doesn''t perform, then we are not solving problems; we are creating them.</li><li><strong>Golden Rule Mentality</strong> — Treat others including the company and the customer the way you''d want to be treated.</li><li><strong>Colossians 3:23</strong> — We work hard, and we play hard, for the Lord.</li><li><strong>Integrity is Key</strong> — We believe that character matters, all the time.</li><li><strong>We Are a Team</strong> — We win together, we lose together. We work together as a team to accomplish remarkable things that we could not do alone.</li><li><strong>Clean is King</strong> — A clean workspace is an efficient workspace.</li><li><strong>Innovative Thinking</strong> — We are committed to building a company full of 3-dimensional thinkers.</li><li><strong>Have Fun</strong> — A career doesn''t have to be work.</li></ol>', 2, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Sales Representative Roles', 'sales-representative-roles', '<h2>Sales Representative Roles</h2><p>At Innovative Air Technologies (IAT), our Sales Representatives play a vital role in driving the success of our company. As the face of IAT to our customers, they embody our core values and are instrumental in fostering long-lasting relationships.</p><blockquote>Below is an outline of the key roles and responsibilities we entrust to our Sales Representatives:</blockquote><ol><li><strong>Customer Relationship Management:</strong> Sales Representatives are responsible for building and maintaining strong relationships with both existing and potential customers. They serve as the primary point of contact for clients, addressing inquiries, providing solutions, and ensuring customer satisfaction throughout the sales process.</li><li><strong>Product Knowledge and Expertise:</strong> Our Sales Representatives possess in-depth knowledge of our products and services. They stay updated on industry trends, technological advancements, and competitive landscapes to effectively communicate the value proposition of IAT offerings to customers.</li><li><strong>Sales Target Achievement:</strong> Meeting and exceeding sales targets is a fundamental aspect of the Sales Representative role. They actively pursue sales opportunities, negotiate contracts, and close deals in alignment with company objectives.</li><li><strong>Market Research and Analysis:</strong> Sales Representatives conduct thorough market research to identify potential leads, understand customer needs, and evaluate market trends. This information is utilized to formulate strategic sales approaches and tailor solutions to meet client requirements.</li><li><strong>Collaboration with Internal Teams:</strong> Effective communication and collaboration with internal departments such as Marketing, Product Management, and Customer Support are essential. Sales Representatives provide valuable insights from the field to inform product enhancements, marketing strategies, and customer support initiatives.</li><li><strong>Adherence to Company Policies and Procedures:</strong> Sales Representatives adhere to company policies, procedures, and ethical standards in all interactions with customers, partners, and colleagues. They uphold the reputation and integrity of IAT in every aspect of their work.</li></ol><p>Rep Locator: <a href="https://www.dehumidifiers.com/customer-area-rep-map">https://www.dehumidifiers.com/customer-area-rep-map</a></p>', 3, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Keys to a Successful Partnership', 'keys-to-a-successful-partnership', '<h2>Keys to a Successful Partnership</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Two-column table — Innovative Air Technologies commitments vs. Representative commitments — re-upload via admin editor</figcaption></figure><ul><li><strong>IAT provides:</strong> Differentiated products &amp; solutions that deliver added value to customers; quality at a competitive price; product availability to meet customer needs; sales support that returns solutions within 24 hours; moisture loads, system design, equipment selection, documentation, success stories, responsiveness and training; customer service that goes above and beyond expectations (job site start-up assistance, phone support, software support, technical service and parts).</li><li><strong>Representative commits to:</strong> Uphold the Vision and Core Values of Innovative Air Technologies; carry non-conflicting product lines; regard Innovative Air Technologies as a major piece of Representative''s revenue and profit financial portfolio; sell full Innovative Air Technologies Line: Compact Series, Rotor Series, IDP Series products; cover all aspects of the new construction markets, seek repair/replace opportunities with local market key influencers; design build contractors, engineers, building owners/operators; develop &amp; achieve annual Innovative Air Technologies business plan, developed each year in December; continually grow Innovative Air Technologies sales in territory; participate fully in training &amp; regional meetings.</li></ul>', 4, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Scope of Authority', 'scope-of-authority', '<h2>Scope of Authority</h2><p>Representative has authority to promote the sale of available Innovative Air Technologies products and services and to solicit purchase orders therefore within Representative''s assigned territory. Representative has no other authority, and specifically, has no authority to make any representation, waive any right, incur any obligation or in any other way to act on behalf of Innovative Air Technologies. All requests to expand Representative''s authority for specific purposes in specific circumstances must be submitted in writing to Innovative Air Technologies'' President. Such authority shall not exist unless and until Representative receives written authorization duly signed by Innovative Air Technologies'' President.</p>', 5, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Ethical Standard & Loyalty', 'ethical-standard-and-loyalty', '<h2>Ethical Standard &amp; Loyalty</h2><p>Representative shall in all events conduct its efforts as sales representative for Innovative Air Technologies in accordance with all applicable laws, rules and regulations of any governing authority, and Representative shall conduct such efforts according to the highest ethical standards for honesty, integrity, and fair dealing. Any conduct of the Representative in violation of law or contrary to ethical standards is outside the scope of Representative''s authority, as sales representative for Innovative Air Technologies, and Representative shall not be bound thereby. Representative shall be liable to indemnify and hold harmless Innovative Air Technologies from and against any and all loss occasioned by illegal or unethical conduct of Representative.</p><p>Recognizing an important duty of loyalty, Representative shall not engage in any conduct that conflicts with the interests of Innovative Air Technologies, including but not limited to the promotion and sale of competitive products or services or the disclosure of Innovative Air Technologies'' sensitive business information.</p>', 6, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Courtesy, Cooperation, and Communication', 'courtesy-cooperation-and-communication', '<h2>Courtesy, Cooperation, and Communication</h2><p>Representative''s conduct on behalf of Innovative Air Technologies in all circumstances shall be with appropriate courtesy and decorum, including, but not limited to, dealing politely and respectfully with Innovative Air Technologies'' customers, support staff and clerical personnel.</p><p>When appropriate or when requested by Innovative Air Technologies, Representative shall fully cooperate with other sales representatives or other persons identified by Innovative Air Technologies in connection with Innovative Air Technologies'' business activities.</p><p>If Innovative Air Technologies has been specified on a job where more than one Representative is involved, Innovative Air Technologies should be notified in writing in advance of quoting the job to properly communicate to all parties and give credit where credit is due.</p><p>In matters that affect correct orders or instructions, communication should be confirmed in writing, which may be via e-mail. A simple rule — if it''s important, confirm it.</p>', 7, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Training Schedule', 'training-schedule', '<h2>Training Schedule</h2><p>Upon becoming a manufacturer''s representative, it''s IAT''s responsibility to provide at minimum 2 training visits to the rep. One virtually through Teams where IAT core values, products, and technologies are highlighted. Second training is in person at either the factory of IAT, or at the rep''s location. These two sessions are to happen within 60 days of rep onboarding to ensure fast adherence and training of equipment.</p>', 8, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Product Information', 'product-information', '<h2>Product Information</h2><h3>General Information</h3><ul><li>We specialize in applications that require dry air under 45°F dewpoint.</li><li>Our equipment removes moisture from the air by means of a desiccant: a substance that absorbs water in a vapor state.</li><li>This desiccant is fused into paper sheets, then wound into a wheel, called the rotor.</li><li>The rotor is divided into two sectioned air streams: processing and reactivation.</li><li>When the processed air stream passes through the rotor, the moisture in that air stream is adsorbed by the rotor, leaving the dried air to be sent to the designated space.</li><li>The water from the processed air now needs to be removed from the rotor to continue the dehumidification process. The reactivation air stream provides this task.</li><li>Reactivation air is heated to 270°F – 320°F. This heat passes over the rotor and sets free the bound water. This extremely humid air is ducted outside.</li></ul><h3>CFM</h3><p>75 – 30,000 CFM</p><h3>Compact Series Dehumidifiers</h3><p>Compact Series dehumidifiers are simple, stand-alone desiccant dehumidifiers perfect for smaller environments that require low humidity conditions. Typical for walk-in coolers or smaller labs. The Compact Series dehumidifiers come standard with all the necessary features to produce very dry air: fans, desiccant wheel, heater, controls, filters. Again, a stand-alone system ready for action.</p><p><strong>Models Include:</strong></p><ul><li>70IEC</li><li>150IEC</li><li>200IEC</li><li>600IEC</li></ul><h3>Rotor Series Dehumidifiers</h3><p>600 – 30,000 CFM, considered a big brother to the Compact Series dehumidifiers. Standard, stand-alone dehumidifiers.</p><h3>IDP Series Dehumidifiers</h3><p>The IDP Series (Integrated Dehumidification Package) is a customized version of the Rotor and Compact series dehumidifiers. It comes integrated with just about any HVAC component needed to create a one of kind turn-key air handling solution. This product can include temperature control, humidity control, filtration, humidification for winter operations as well as customized control options.</p><h3>Common Applications</h3><ul><li>Aerospace</li><li>Agriculture</li><li>Automotive</li><li>Colleges &amp; Universities</li><li>Electronics</li><li>Food Processing</li><li>Glass Lamination</li><li>Hospitals</li><li>Ice Rinks</li><li>Medical Labs</li><li>Military Storage</li><li>Museums &amp; Archival Storage</li><li>Pharmaceutical Manufacturing</li><li>Plastic Injection/Molding</li><li>Research Facilities</li></ul><figure class="img-missing"><figcaption>📷 Image from Trainual: YouTube video — Demystifying Desiccant Dehumidification with David Schurk — re-upload via admin editor</figcaption></figure>', 9, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'new-rep-onboarding'
ON CONFLICT (module_id, slug) DO NOTHING;
