SELECT m.id, 'Key Contacts', 'key-contacts', '<h2>Key Contacts</h2><ul><li><strong>Sales Inquiry</strong> — Kacy Orr, President</li><li><strong>Sales Inquiry</strong> — David Schurk, National Sales Manager</li><li><strong>Service Inquiries</strong> — Andy Schuhardt, Field Service Manager</li><li><strong>Production &amp; Engineering Inquiries</strong> — James Pope, Director of Engineering &amp; Production</li><li><strong>Operations Inquiries</strong> — Crystal Hill, Director of Operations</li><li><strong>Marketing &amp; Design Inquiries</strong> — Summer Neal, Marketing Manager</li></ul>', 11, TRUE, 1
