-- ── Lessons: How we Use Trainual at IAT ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Trainual?', 'what-is-trainual', '<h2>What is Trainual?</h2><p><strong>Welcome to Trainual</strong></p><p>Our business thrives on <strong>repeatable processes</strong>. They are incredibly important in ensuring that we maintain world class quality and consistency in everything we do. The consistency we achieve through these processes is what drives our business growth, benefiting everyone involved!</p><p>To make all of this possible, we recognized the need for a central hub to document these processes. That&apos;s where Trainual comes in. <em><strong>Think of it as the playbook for our business, a comprehensive guide for everything we do here.</strong></em></p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF of Dwight Schrute from The Office saying &quot;Let&apos;s do this!&quot; — re-upload via admin editor</figcaption></figure><p><em>Next, we&apos;ll go over the expectations for using Trainual at Innovative Air Technologies.</em></p>', 0, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Expectations', 'expectations', '<h2>Expectations</h2><p>We&apos;ve invested a lot of time, effort, money, a little bit of sweat (Summer may have cried a few tears) to build our playbook.</p><p>Our goal is for Trainual to be the <strong><em>ONE</em></strong> source of truth for <strong><em>EVERYTHING</em></strong> we do at IAT. No more tribal knowledge.</p><p>If it&apos;s in Kacy&apos;s brain, it will be on Trainual (<em>eventually</em>).</p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with caption &quot;The age of chaos is over!&quot; — re-upload via admin editor</figcaption></figure><p><strong>Now, there are 2 things we need YOU to do:</strong></p><h3>1. Check Trainual FIRST!</h3><p>If you have a question about any part of our business or your job, look it up in Trainual first. It&apos;s super easy! Just use the <strong>Search</strong> tool on the top of the page to ask questions and find your answers.</p><h3>2. If it&apos;s not in Trainual, let us know!</h3><p>If you can&apos;t find the answers you&apos;re looking for in Trainual, let your manager know. First, so they can answer your question. And second, so they can make sure it gets documented in Trainual.</p><p><em>Next, we&apos;ll cover a few other features and tools for using Trainual.</em></p>', 1, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Trainual University', 'trainual-university', '<h2>Trainual University</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Trainual University logo/badge — re-upload via admin editor</figcaption></figure><p>Trainual University is where you&apos;ll learn how to use Trainual&apos;s program features. Trainual University is optional but <em><strong>highly recommended.</strong></em></p><h3>This will include:</h3><ol><li>A short subject to show you how to use Trainual U.</li><li>A Trainual orientation course designed just for you and how you&apos;ll be using Trainual.</li></ol><h3>How to access Trainual U</h3><p>Click the card on your Home page or click your avatar menu and select <strong>Go to Trainual U</strong>. This will open Trainual U in a new tab in your browser.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Screenshot of the Trainual avatar dropdown menu showing &quot;Go to Trainual U&quot; option — re-upload via admin editor</figcaption></figure>', 2, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Download the App', 'download-the-app', '<h2>Download the App</h2><p>Trainual! There&apos;s an app for that.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Trainual app icon (purple with &quot;T&quot;) — re-upload via admin editor</figcaption></figure><p>With the app, you can easily search, view, complete, and access your assigned content anytime, anywhere, right on your phone or tablet!</p><p><strong>Click below to download the correct version.</strong></p><ul><li><a href="https://play.google.com/store/apps/details?id=com.trainual.trainual">Get it on Google Play</a></li><li><a href="https://apps.apple.com/app/trainual/id1477396049">Download on the App Store</a></li></ul>', 3, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'If you need help with Trainual', 'if-you-need-help-with-trainual', '<h2>If you need help with Trainual</h2><p>Our <strong>ONSITE</strong> Trainual Expert is:</p><p><strong>Summer Neal</strong><br><a href="mailto:summer@dehumidifiers.com">summer@dehumidifiers.com</a></p><p>Send an email or just stop by her office, you could use the walk and she needs human interaction.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with caption &quot;Come on!&quot; (humorous encouragement to reach out) — re-upload via admin editor</figcaption></figure>', 4, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'onboarding' AND m.slug = 'how-we-use-trainual-at-iat'
ON CONFLICT (module_id, slug) DO NOTHING;

-- ── Lessons: Company Commitments ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Commitment to You', 'our-commitment-to-you', '<h2>Our Commitment to You</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Commitment to Open Communication" — re-upload via admin editor</figcaption></figure>
<p>At Innovative Air Technologies, we want to make sure everything runs smoothly and everyone''s on the same page. That''s why we''ve got these guidelines in place. They''re like our playbook for making decisions, keeping things consistent, and making sure we''re all playing by the rules.</p>
<blockquote><p>Our goal is to create a safe and fun workplace for everyone.</p></blockquote>
<p>These policies are updated periodically to keep up with our growing company — whether it''s new trends in the industry, how we do things around here, or the legal stuff.</p>
<p><strong>Don''t worry, we make sure you''re in the loop with all the latest through emails, meetings, or even a quick training session now and then.</strong></p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: photo of a person holding a binder — re-upload via admin editor</figcaption></figure>
<p><a href="#">Got questions? Curious about something? Just shout.</a></p>
<p>We''re all about keeping the lines open, building trust, and making sure everyone feels confident about how things work around here.</p>', 0, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview', 'non-harassment-overview', '<h2>Overview</h2>
<p>Individuals at Innovative Air Technologies have the right to work in an environment free from harassment and discrimination. This right is not only supported by company policies but also enshrined in various state and federal laws. Employees can be assured that any form of harassment or discrimination will not be tolerated and will be met with appropriate disciplinary actions.</p>
<p>As a company operating in Georgia, Innovative Air Technologies ensures that its non-harassment and non-discrimination policies are in full compliance with the state''s laws and regulations. By aligning with legal requirements, the company demonstrates its commitment to upholding the rights and well-being of its employees while fostering a culture of respect and equality.</p>', 1, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why We Have an Anti-discrimination Policy', 'why-we-have-an-anti-discrimination-policy', '<h2>Why We Have an Anti-discrimination Policy</h2>
<p>Unfortunately, because it''s necessary. However, we have put in place a set of guidelines to protect you from being discriminated against or harassed. We have outlined what we consider these things to be. It''s our duty to you to create a happy and healthy work environment — this means eliminating all possibilities of discriminatory actions and behaviors.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "Not up in here — NOT UP IN HERE!" — re-upload via admin editor</figcaption></figure>
<p>At IAT, we are <strong>committed</strong> to providing a workplace that is free from discrimination and harassment.</p>
<p>We do this so you know that we have your back, no matter what!</p>', 2, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Harassment?', 'what-is-harassment', '<h2>What is Harassment?</h2>
<p><strong>Harassment is <em>ANY</em> unwelcome conduct that is based on one of the below or any other social characteristics.</strong></p>
<h3>Characteristics:</h3>
<ul>
  <li>Race</li>
  <li>Color</li>
  <li>Religion</li>
  <li>Sex (including pregnancy)</li>
  <li>National origin</li>
  <li>Age</li>
  <li>Disability or genetic information</li>
  <li>Marriage / civil partnership</li>
  <li>Gender identity / sexual orientation</li>
</ul>', 3, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Sexual Harassment', 'sexual-harassment', '<h2>Sexual Harassment</h2>
<p><strong>Sexual harassment is defined as unwelcome sexual advances, requests for sexual favors and other verbal, visual or physical conduct of a sexual nature, when:</strong></p>
<ol>
  <li>Submission to such conduct is made either explicitly or implicitly a term or condition of an individual''s employment.</li>
  <li>Submission to or rejection of such conduct by an individual is used as the basis for employment decisions affecting such individual; or</li>
  <li>Such conduct has the purpose or effect of unreasonably interfering with an individual''s work performance or creating an intimidating, hostile or offensive working environment.</li>
</ol>
<p>Examples of sexual harassment include but are not limited to: unwelcome or unsolicited sexual advances; displaying sexually suggestive material; unwelcome sexual flirtations, advances or propositions; suggestive comments; verbal abuse of a sexual nature; sexually oriented jokes; crude or vulgar language or gestures; graphic or verbal commentaries about an individual''s body; display or distribution of obscene materials; physical contact such as patting, pinching or brushing against someone''s body; or physical assault of a sexual nature.</p>', 4, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'About Discriminatory Behavior', 'about-discriminatory-behavior', '<h2>About Discriminatory Behavior</h2>
<p>Discrimination is the act of <strong>treating a person or group differently, unjustly, or negatively based on their membership in a particular social category</strong>. This unequal treatment can take many forms, and can be intentional or unintentional.</p>
<p><strong>Below are a few examples of what we consider to be discriminatory behavior…</strong></p>
<h3>Examples of discrimination:</h3>
<ul>
  <li>Hiring managers disproportionately hiring / disqualifying candidates of a certain gender due to their own biases, knowingly.</li>
  <li>Managers that overlook employees with specific protected characteristics (such as race, religion) for raises / promotions and cannot prove they did so fairly.</li>
  <li>Someone making sexist / racist comments.</li>
  <li>Sending emails belittling an employee about any of their protected characteristics (such as race, religion, gender presentation, nationality, etc.).</li>
</ul>
<p>Obviously, this is not an exhaustive list. If you feel you have been harassed or discriminated against, please let your manager or HR rep know.</p>', 5, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What To Do if You See or Experience Discrimination', 'what-to-do-if-you-see-or-experience-discrimination', '<h2>What To Do if You See or Experience Discrimination</h2>
<p><strong>If you or someone you know is being discriminated against or harassed, tell your supervisor or HR right away!</strong></p>
<p>Any company employee who feels that he or she has been harassed or discriminated against or has witnessed or become aware of discrimination or harassment in violation of these policies, should bring the matter to the immediate attention of his or her supervisor, HR, or any other manager. We will promptly investigate all allegations of discrimination, harassment and act as appropriate based on the outcome of the investigation.</p>
<p>An investigation and its results will be treated as confidential to the extent feasible, and the company will take appropriate action based on the outcome of the investigation.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "Hello, I need to tattle" — re-upload via admin editor</figcaption></figure>
<p><strong>HR will spearhead an investigation of your claim, look into the situation, and then decide the best course of action for resolution for both the victim and the perpetrator.</strong></p>
<p><strong>NOTE:</strong> No employee will be retaliated against for making a complaint in good faith regarding a violation of these policies, or for participating in good faith in an investigation pursuant to these policies. If an employee feels he/she has been retaliated against, the employee should file a complaint using the procedures set forth above.</p>', 6, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Anti-discrimination Policy', 'our-anti-discrimination-policy', '<h2>Our Anti-discrimination Policy</h2>
<p>This is simple: <strong>We do not allow or tolerate, under any circumstance, ANY behavior, or actions that we or others may consider discriminatory or harassing.</strong></p>
<blockquote><p>Again, zero tolerance!</p></blockquote>
<p>Our anti-discrimination policy prohibits discrimination and harassment on the basis of an individual''s race, color, religion, national origin, sex, gender identity, sexual orientation, age, disability, or any other protected characteristic.</p>
<h3>Anti-discrimination policy:</h3>
<ol>
  <li><strong>Discrimination and harassment are prohibited</strong> in all aspects of employment, including hiring, promotion, compensation, benefits, training, discipline, and termination.</li>
  <li>Employees who <strong>experience</strong> harassment are <strong>encouraged</strong> to report the incident to their direct manager, or to HR. Employees who <strong>witness</strong> discrimination or harassment are <strong>required</strong> to report the incident to their direct manager or to HR.</li>
  <li>Reports of discrimination or harassment will be <strong>investigated promptly and thoroughly</strong>, and confidentiality will be maintained to the extent possible.</li>
  <li><strong>Retaliation</strong> against individuals who report discrimination or harassment or who participate in an investigation is <strong>strictly prohibited</strong>.</li>
  <li>Employees who <strong>engage</strong> in discrimination or harassment will be subject to disciplinary action, up to and including <strong>termination of employment</strong>.</li>
</ol>
<p><strong>We are committed to creating a workplace that is free from discrimination and harassment, and we will take all necessary steps to prevent and address incidents of discrimination and harassment.</strong></p>', 7, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How We Prevent Discrimination and Harassment', 'how-we-prevent-discrimination-and-harassment', '<h2>How We Prevent Discrimination and Harassment</h2>
<p><strong>First and foremost, we encourage a culture of inclusion and mutual respect.</strong></p>
<p>To avoid potential harassment situations altogether, and to make sure we handle every case fairly and lawfully, we also do the following…</p>
<h3>Our steps towards prevention:</h3>
<ul>
  <li>We have a set series of rules that apply to job-related hiring, promoting, and rewarding employees to avoid accidental/purposeful discrimination.</li>
  <li>All compensation / benefits will be based on position, seniority, qualification, and performance — NOT based on protected characteristics.</li>
  <li>We make appropriate adjustments for all employees with disabilities.</li>
  <li>We ask that managers keep a log of their decisions regarding promotion / demotion, or anything really, of current employees or job candidates.</li>
</ul>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How We Support Victims of Harassment', 'how-we-support-victims-of-harassment', '<h2>How We Support Victims of Harassment</h2>
<p>We are here to help and protect <strong>YOU</strong>! So that we can ensure you feel safe and accepted at work, HR is always on the lookout for situations where discrimination might occur. What does this look like?</p>
<p><strong>What we do about allegations of harassment:</strong></p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "Sherlock Homeboy" — re-upload via admin editor</figcaption></figure>
<ul>
  <li>Looking into all similar claims about an accused individual to see if the problem has become systematic.</li>
  <li>Keeping an eye on data from the company — making sure we are avoiding discriminatory behaviors (such as hiring/firing employees of a certain race/gender/religion by a manager).</li>
  <li>Conduct private and discrete interviews to gather information about the situation/individual accused.</li>
</ul>', 9, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Disciplinary Action', 'disciplinary-action', '<h2>Disciplinary Action</h2>
<p>As we have previously mentioned, we have a <strong>zero-tolerance policy</strong> for harassment of any kind, and disciplinary action will be severe, usually ending in termination. Each case will be reviewed thoroughly and fairly to determine the appropriate outcome.</p>
<p>If an infraction is found to be criminal in nature, we will inform and fully cooperate with the authorities to investigate the incident.</p>', 10, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Our Commitment', 'drug-alcohol-our-commitment', '<h2>Our Commitment</h2>
<p><strong>Our commitment at Innovative Air Technologies to maintaining a drug-free and alcohol-free workplace is paramount to ensuring the safety and well-being of all our employees.</strong></p>
<p>By upholding this policy, we create a work environment that is not only compliant with regulations but also fosters a culture of trust and accountability.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Drug and Alcohol Policy at Innovative Air Technologies" — re-upload via admin editor</figcaption></figure>
<p>Emphasizing the importance of a drug and alcohol-free workplace demonstrates our dedication to promoting a safe and healthy environment for all employees. This commitment is reflected in our hiring practices, ongoing education programs, and regular screenings to ensure compliance with our zero-tolerance policy.</p>', 11, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Drug &amp; Alcohol Policy', 'drug-and-alcohol-policy', '<h2>Drug &amp; Alcohol Policy</h2>
<p><strong>Employees are prohibited from unlawfully consuming, distributing, possessing, selling, or using controlled substances while on duty.</strong></p>
<p>In addition, employees may not be under the influence of any controlled substance, such as drugs or alcohol, while at work, on company premises or engaged in company business.</p>
<p><strong>Prescription drugs or over-the-counter medications, taken as prescribed, are an exception to this policy.</strong></p>
<p>Anyone violating this policy may be subject to disciplinary action, up to and including termination.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF of a person at a door (The Office) — re-upload via admin editor</figcaption></figure>
<p><strong>All newly hired employees are required to have a pre-hire drug screening.</strong></p>
<p>IAT reserves the right to randomly require drug screening at its discretion.</p>', 12, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Come on in!', 'come-on-in', '<h2>Come on in!</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF from Seinfeld showing someone at a door — re-upload via admin editor</figcaption></figure>
<p>At Innovative Air Technologies, we like to keep things chill and open. With our <strong><em>open door policy</em></strong>, no matter if you''re just starting out or if you''re on the leadership team, you can just pop in and chat with your supervisors anytime.</p>
<ul>
  <li>Got an idea?</li>
  <li>A bit of feedback?</li>
  <li>Something bugging you?</li>
  <li>Tell them about it.</li>
</ul>
<p><strong>We want to make sure everyone feels heard and valued.</strong></p>
<p>We get that every single person here is key to making IAT a world-class environment, and by keeping the lines of communication wide open, we can sort out any issues fast, keep everyone happy, and make our workplace not just productive but also a pretty great place to be.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Open Door Policy Explained" — re-upload via admin editor</figcaption></figure>', 13, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview', 'payday-overview', '<h2>Overview</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: video embed titled "Getting Paid" — re-upload via admin editor</figcaption></figure>
<p><strong>Paychecks/Direct Deposits are distributed every Thursday. If the pay date lands on a holiday, paychecks will be distributed on the closest business day before the holiday.</strong></p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: GIF captioned "SHOW" (Jerry Maguire money scene) — re-upload via admin editor</figcaption></figure>
<p>The paycheck will reflect work performed for the week prior to the pay date. Paychecks include salary or wages earned less any mandatory or elected deductions.</p>
<ol>
  <li>Mandatory deductions include federal or state withholding tax, and other withholdings.</li>
  <li>Elected deductions are deductions authorized by the employee, and may include, for example, contributions to benefit plans.</li>
</ol>
<p><a href="#">Employees may contact HR to obtain the necessary authorization forms to requesting additional deductions from their paychecks.</a></p>
<p>Notify a supervisor if the paycheck appears to be inaccurate. If there is an issue with direct deposit, or if it has been misplaced, IAT reserves the right to charge a replacement fee for any lost paychecks.</p>
<p>Advances on paychecks are not permitted. Information regarding final paychecks can be found under the termination section of this handbook.</p>
<p>Any change in bank account, name, address, telephone number, marital status or number of exemptions claimed by an employee must be reported to HR immediately.</p>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-commitments'
ON CONFLICT (module_id, slug) DO NOTHING;

-- ── Lessons: Company Policies ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why We Have Company Policies', 'why-we-have-company-policies', '<h2>Why We Have Company Policies</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "What''s the Policy Again?" graphic — re-upload via admin editor</figcaption></figure>
<p>So, why do we have company policies? Well, think of it as our secret sauce for making things run smoothly here at Innovative Air Technologies. It''s all about setting up clear rules and guidelines so everyone knows what''s what — from who does what, to how we all should behave. It''s like having a roadmap for work, making sure we''re all heading in the same direction and staying on track.</p>
<p>Now, we all know the business world doesn''t stand still, right? It''s always changing, and so are we. That''s why we update our policies regularly, tweaking them to stay in line with the latest industry standards, legal stuff, and what we need to keep our operations humming. And we''ll be sure to keep you in the loop with any changes because <strong>we''re all in this together.</strong></p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "We''re All In This Together" graphic — re-upload via admin editor</figcaption></figure>
<p>Here at Innovative Air Technologies, putting our people first is what we''re all about. We believe in setting up policies that are not just rules for the sake of rules, but ones that actually support and respect everyone. It''s our way of making sure this place isn''t just a workplace, but a community where everyone feels valued, protected, and part of something bigger. Pretty cool, right?</p>
<h3>And let''s talk about talking...</h3>
<p>It''s a big deal for us. Keeping the lines of communication wide open between the management team and you guys is key.</p>
<p>Got a question?</p>
<p>A concern?</p>
<p>A suggestion?</p>
<p><strong>We''re all ears.</strong></p>
<p>We like to keep things open and honest to help us build a place where trust isn''t just a word, but how we roll. Together, we''re all about making Innovative Air Technologies not just a great place to work, but a place where work feels great.</p>', 0, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Policy Manual', 'company-policy-manual', '<h2>Company Policy Manual</h2>
<p>As a new member of the Innovative Air Technologies team, it is important that you download and review our company policy manual. This manual contains important information that we cover in this training course about our company''s policies and procedures, as well as guidelines for conduct in the workplace. It is essential that you familiarize yourself with this document to ensure that you are aware of our expectations and standards.</p>
<p>Once you have downloaded the company policy manual, please retain it for your records. This document serves as a valuable resource for you to refer back to whenever needed. If you have any questions or require clarification on any of the policies outlined in the manual, please do not hesitate to reach out to us. We are always available to answer any questions you may have and provide guidance as needed.</p>
<p><a href="https://www.dehumidifiers.com">IAT_Company_Policy_Manual_rev8.2025.pdf</a></p>', 1, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Professional Conduct Matters', 'professional-conduct-matters', '<h2>Professional Conduct Matters</h2>
<blockquote><p><em>Our company values everyone getting along, acting professionally, and just being all-around decent to each other.</em></p></blockquote>
<p>It''s all about making sure we''ve got a cool, safe, and super productive place to work. Be kind, polite, and considerate of how others are feeling and what they need. Plus, working well together, whether it''s with your teammates or the bosses, is a big deal around here.</p>
<p>Just a heads up, though — if someone''s not playing by these rules and gets a bit out of line, there might be some consequences.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "That one might have an after effect" meme — re-upload via admin editor</figcaption></figure>', 2, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why We Have a Dress Code', 'why-we-have-a-dress-code', '<h2>Why We Have a Dress Code</h2>
<p>At Innovative Air Technologies, we''re all about creating a culture that''s professional, respectful, and, most importantly, safe.</p>
<p>When everyone brings their A-game, dressed for success and treating each other right, it sets the tone for the whole place. It''s about showing our best selves to our customers, partners, and each other.</p>
<p>So, we''ve put together this little guide to help everyone understand what''s expected when it comes to how we act and dress around here.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Employee in IAT-branded clothing — re-upload via admin editor</figcaption></figure>', 3, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Dress Code: General Guidelines', 'dress-code-general-guidelines', '<h2>Dress Code: General Guidelines</h2>
<p>At Innovative Air Technologies (IAT), we believe that an employee''s personal appearance and hygiene reflect the company''s character and professionalism. Our dress code is designed to ensure that employees are comfortable, safe, and appropriately represent the company while performing their duties.</p>
<ul>
<li>Employees are expected to dress appropriately based on their individual work responsibilities and positions.</li>
<li>Professional attire is required during external meetings, with IAT company shirts or designated attire for customer or vendor visits, ensuring a consistent and professional image.</li>
<li>Clothing should be clean, well-maintained, and free from rips, tears, or offensive logos or slogans.</li>
<li>Personal hygiene should be maintained to a high standard.</li>
</ul>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Dress Code General Guidelines video thumbnail — re-upload via admin editor</figcaption></figure>', 4, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Dress Code: Prohibited Attire', 'dress-code-prohibited-attire', '<h2>Dress Code: Prohibited Attire</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "How ''Bout No" meme graphic — re-upload via admin editor</figcaption></figure>
<h3>So, here''s the deal:</h3>
<ul>
<li>First off, let''s keep it classy and respectful with our outfits. That means no clothes with rude words, pictures, or catchphrases. We''re all about good vibes here.</li>
<li>Next, we love to be comfy, but let''s save the super casual stuff like sweatpants, flip-flops, or tank tops for the weekends, unless your manager says it''s cool.</li>
<li>And lastly, let''s aim for clothes that aren''t too revealing or super tight. We''re all for expressing yourself, but let''s keep it professional.</li>
</ul>
<blockquote><p><strong>Thanks for keeping the workplace awesome for everyone!</strong></p></blockquote>', 5, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Personnel Files', 'personnel-files', '<h2>Personnel Files</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Understanding Your Personnel File video thumbnail — re-upload via admin editor</figcaption></figure>
<blockquote><p><em>Our policy is established to ensure transparency, privacy, and security in the handling of employee records.</em></p></blockquote>
<p>We recognize that personnel files contain sensitive and confidential information, ranging from employment history to performance evaluations. This policy is in place to strike a balance between employee rights to access their own information and the need to safeguard this data against unauthorized access.</p>
<p>Having this policy allows employees to review and understand the information kept in their files, fostering an environment of trust and open communication. It also ensures that our company adheres to legal standards regarding data privacy and employee rights. By regulating access to personnel files, we protect the integrity of employee data, maintain confidentiality, and uphold our commitment to ethical and responsible information management. This policy is a key part of our dedication to creating a respectful, secure, and transparent workplace for all our employees.</p>', 6, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Access to Personnel Records', 'access-to-personnel-records', '<h2>Access to Personnel Records</h2>
<p>So, here''s the deal: The company has a file for each and every one of us, kind of like our own little dossier. They try to keep it under wraps as much as they can.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "It''s classified" meme — re-upload via admin editor</figcaption></figure>
<p>If you''re curious about what''s in your file, you can totally ask to see it. Just say the word!</p>
<p>Now, it''s super important that this file has got all the right info about you. If anything changes — like your name, where you live, your phone number, who to call in an emergency, or even your marital status — you''ve gotta let the company know.</p>
<p>Oh, and if by chance you forget to update your info and it ends up costing you, just remember, the company''s not picking up the tab for that. That''s on you, buddy.</p>', 7, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Privacy at IAT', 'privacy-at-iat', '<h2>Privacy at IAT</h2>
<blockquote><p><em>At Innovative Air Technologies, we''re all about creating a work environment of trust and mutual respect.</em></p></blockquote>
<p>Keeping things running smoothly, protecting our assets, and making sure we''re all on the right side of the law are super important to us. That''s why we have guidelines in place about privacy and how we all should use the company''s gear.</p>
<p>We''ve tried to strike a balance with this policy. This helps IAT work like a well-oiled machine while also looking after our assets and standing by our values. We''re all in this together, so we encourage everyone to stay professional and make smart choices with the resources we''ve got.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Privacy Policy Introduction video thumbnail — re-upload via admin editor</figcaption></figure>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Property and Access', 'company-property-and-access', '<h2>Company Property and Access</h2>
<blockquote><p><strong>Company property refers to the physical assets owned by a business that are essential for its operations.</strong></p></blockquote>
<p>For Innovative Air Technologies, assets may include office buildings, manufacturing facilities, equipment, machinery, vehicles, computers, furniture, and other tangible assets used in the daily operations of the company. These assets are crucial for the business to function effectively and serve its customers.</p>
<p>In addition to tangible assets, <strong>company property also encompasses intellectual property</strong> such as patents, trademarks, copyrights, and trade secrets that are valuable assets for Innovative Air Technologies. These intellectual properties are protected by law and play a vital role in maintaining the company''s competitive edge in the market.</p>
<p>Access to company property is typically restricted to authorized personnel only to ensure security and prevent unauthorized use or theft. Employees may be granted access to specific company property based on their job responsibilities and level of authorization. It is important for employees to understand and adhere to the company''s policies and procedures regarding the use and protection of company property to maintain a safe and secure work environment.</p>', 9, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Expectation of Privacy', 'expectation-of-privacy', '<h2>Expectation of Privacy</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Could you give us some privacy for, like, one second?" meme — re-upload via admin editor</figcaption></figure>
<blockquote><p><strong>When it comes to company property and access, Innovative Air Technologies has established clear guidelines for employees to follow. The company retains the right to access, monitor, and inspect all company property at any time. This policy is in place to ensure compliance with security protocols and to protect the interests of the organization.</strong></p></blockquote>
<p>Employees should be aware that when using or storing personal items or information on company property, <strong>they should not expect privacy.</strong> This includes company-issued devices, email accounts, and storage areas. By using company property, employees are consenting to the monitoring and inspection of their activities to maintain a secure and productive work environment.</p>', 10, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Company Property?', 'what-is-company-property', '<h2>What is Company Property?</h2>
<blockquote><p><em>This policy is to ensure that company property is used appropriately for business purposes and returned in good condition when an employee leaves the company.</em></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: What is Company Property video thumbnail — re-upload via admin editor</figcaption></figure>
<p>Company property, such as equipment, vehicles, telephones, computers, and software, is not for private use. These devices are to be used strictly for company business and are not permitted off grounds unless authorized. Company property must be used in the manner for which it was intended. Upon termination, employees are required to surrender any company property they possess.</p>
<h3>Items to remember:</h3>
<ol>
<li><strong>Business Use Only:</strong> Company property, including equipment, computers, phones, and software, is to be used for business purposes only.</li>
<li><strong>Authorization for Private Use:</strong> If there is a need to use company property for private use, employees must seek approval from their manager.</li>
<li><strong>No Taking Home:</strong> Company property should not be taken home without proper authorization.</li>
<li><strong>Return Upon Departure:</strong> When an employee leaves the company, all company property must be returned as they are owned by the company.</li>
</ol>
<blockquote><p><strong>PLEASE NOTE:</strong></p>
<ul>
<li>Misuse of company property for private use without authorization is not allowed.</li>
<li>Taking company property home without permission can result in disciplinary action.</li>
<li>Failure to return company property upon departure may lead to legal consequences.</li>
</ul></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "I Have a Tip" meme — re-upload via admin editor</figcaption></figure>
<h3>Some tips for you...</h3>
<ul>
<li>Communicate with your manager if there is a need to use company property for private use.</li>
<li>Keep company property in good condition to ensure smooth operations.</li>
<li>Return all company property promptly when leaving the company to avoid any issues.</li>
</ul>', 11, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Computers', 'company-computers', '<h2>Company Computers</h2>
<blockquote><p><strong>Company computers, internet and emails are a privileged resource, and must be used only to complete essential job-related functions.</strong></p></blockquote>
<ol>
<li>Employees are not permitted to download any "pirated" software, files or programs and must receive permission from a supervisor before installing any new software on a company computer.</li>
<li>Files or programs stored on company computers may not be copied for personal use.</li>
<li>Phones are provided for business use.</li>
<li>The company requests that employees not receive personal calls while on-duty. If urgent, please keep personal calls to a minimum and conversations brief.</li>
<li>Employees are reminded that they should have no expectation of privacy in their use of company computers or other electronic equipment.</li>
<li>Violations of these policies could result in disciplinary action or termination.</li>
</ol>', 12, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Company Tools', 'company-tools', '<h2>Company Tools</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Employee with hard hat — re-upload via admin editor</figcaption></figure>
<ol>
<li>Employees are required to provide their own tools for everyday use. This includes, but is not limited to, hand tools, flashlights, etc.</li>
<li>Specialty tools like rivet guns, welders, etc. are provided by IAT.</li>
<li>Please refer to the company-provided tool list for the comprehensive list.</li>
<li>Employees are also responsible for the safety of their tools.</li>
<li>All tools must be locked up or taken home every night.</li>
<li>IAT is not responsible for lost or stolen tools.</li>
</ol>', 13, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Gossip Policy Overview', 'gossip-policy-overview', '<h2>Gossip Policy Overview</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Handling Gossip in the Workplace video thumbnail — re-upload via admin editor</figcaption></figure>
<p>At Innovative Air Technologies, fostering a positive and collaborative workplace culture is essential to our success. Gossip can undermine trust, disrupt teamwork, and create unnecessary tension among team members. This policy is designed to clarify what constitutes gossip and explain why maintaining a gossip-free environment is crucial for our shared goals.</p>
<blockquote><p><strong>Gossip = Discussing anything negative with someone who cannot resolve the problem.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Don''t Spill the Tea" meme — re-upload via admin editor</figcaption></figure>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Gossip?', 'what-is-gossip', '<h2>What is Gossip?</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "You need to stop spreading life-altering rumors about me" meme — re-upload via admin editor</figcaption></figure>
<blockquote><p><strong>Gossip is any informal communication that spreads unverified, private, or speculative information about others in the workplace.</strong></p></blockquote>
<p>It often includes:</p>
<ul>
<li>Sharing personal details about coworkers without their consent.</li>
<li>Discussing unconfirmed rumors about the company or its operations.</li>
<li>Talking negatively about someone who is not present to address the concerns.</li>
</ul>
<p>Even casual conversations can cross the line into gossip when they are inappropriate, unkind, or potentially harmful. Gossip is not the same as constructive feedback or problem-solving discussions aimed at improving work relationships or performance.</p>
<p><strong>In a nutshell, "gossip" is discussing anything negative about IAT, coworkers, or management with someone who can''t help solve the problem.</strong></p>', 15, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why We Have a Gossip Policy', 'why-we-have-a-gossip-policy', '<h2>Why We Have a Gossip Policy</h2>
<p>Our commitment to integrity and teamwork means creating an environment where everyone feels respected, valued, and supported.</p>
<h3>A gossip-free workplace:</h3>
<ul>
<li>Builds trust and strengthens professional relationships.</li>
<li>Prevents misunderstandings, conflicts, and hurt feelings.</li>
<li>Encourages open, direct communication to resolve issues effectively.</li>
<li>Protects the reputation of employees and the company.</li>
</ul>
<blockquote><p><strong>By addressing gossip proactively, we aim to uphold a culture of professionalism and mutual respect, where everyone can thrive and focus on contributing their best to the team.</strong></p></blockquote>', 16, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Questions to Ask Before You Speak', 'gossip-questions-to-ask', '<h2>Questions to Ask Before You Speak</h2>
<blockquote><p><strong>Ask yourself before you speak:</strong></p></blockquote>
<h3>Is it True?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Is it true?" movie clip — re-upload via admin editor</figcaption></figure>
<p>Know the facts of any information you share. If you have not fact-checked that matter for yourself, avoid talking about it with other co-workers. You can always go to the individual and ask them for yourself. If you don''t feel comfortable doing so, either because of your comfort level with that person or because of the subject matter, you probably shouldn''t be discussing the matter at all.</p>
<h3>Is it Kind?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "The most important part about being famous is being kind" meme — re-upload via admin editor</figcaption></figure>
<p>If it seems like something outrageous or something that you wouldn''t want to get around about you, then don''t share, don''t judge, and don''t assume. Remember — if you can''t say anything nice, don''t say anything at all.</p>
<h3>Is it Necessary?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Is this really necessary?" meme — re-upload via admin editor</figcaption></figure>
<p>Another way to word this is — "Is it helpful for IAT?" In most circumstances, there is nothing productive about gossiping.</p>
<h3>Can this person make a difference?</h3>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Baseball field scene — re-upload via admin editor</figcaption></figure>
<p>If they can''t, discuss it with the person who can.</p>', 17, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Off-Limits Conversations', 'gossip-off-limits-conversations', '<h2>Off-Limits Conversations</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "You must not involve yourself" Shogun clip — re-upload via admin editor</figcaption></figure>
<h3>Conversations That Are Off Limits:</h3>
<ul>
<li><strong>Criminal behaviors</strong></li>
<li><strong>Alcoholism or drug addiction</strong></li>
<li><strong>Infidelity</strong></li>
<li><strong>Personal medical information</strong></li>
<li><strong>Sexuality</strong></li>
<li><strong>Anything that the general public would find reprehensible</strong></li>
</ul>', 18, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Ways to Respond to Gossip', 'gossip-ways-to-respond', '<h2>Ways to Respond to Gossip</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Hold My Beer" meme — re-upload via admin editor</figcaption></figure>
<h3>Ways to respond when approached with gossip:</h3>
<ul>
<li>Remove yourself from the conversation</li>
<li>Politely change the subject</li>
<li>Don''t repeat gossip you overhear</li>
<li>Directly state, "I''m not comfortable talking about __________."</li>
<li>Go directly to your supervisor or management to discuss the matter</li>
</ul>', 19, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Stop the Spread', 'gossip-stop-the-spread', '<h2>Stop the Spread</h2>
<blockquote><p><em>At Innovative Air Technologies, we all have a role in maintaining a respectful and collaborative workplace.</em></p></blockquote>
<p>By actively choosing to stop the spread of gossip, you help create an environment built on trust, integrity, and mutual respect. If you hear gossip, resist the urge to participate and instead redirect the conversation toward positive, productive topics.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Shut It Down" meme — re-upload via admin editor</figcaption></figure>', 20, TRUE, 2
