INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Gossip: Disciplinary Action', 'gossip-disciplinary-action', '<h2>Gossip: Disciplinary Action</h2>
<blockquote><p><strong><em>Engaging in gossip undermines our core values and will not be tolerated.</em></strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "I will not have it" reaction GIF — re-upload via admin editor</figcaption></figure>
<p>Employees who violate this policy may face disciplinary action, which could include verbal or written warnings, suspension, or, in severe cases, termination of employment. Our goal is to address such behavior constructively while protecting the well-being of the team.</p>
<blockquote><p><strong>Thank you for your commitment to fostering a supportive and professional workplace.</strong></p>
<p>Together, we can uphold our values and ensure that Innovative Air Technologies remains a place where everyone can thrive and succeed.</p></blockquote>', 21, TRUE, 2
