INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms Policy: Why We Have This Policy', 'weapons-firearms-why-we-have-this-policy', '<h2>Weapons and Firearms Policy: Why We Have This Policy</h2>
<blockquote><p><strong>At Innovative Air Technologies, maintaining a safe and secure workplace is a top priority.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Weapons and Firearms Policy Intro video thumbnail — re-upload via admin editor</figcaption></figure>
<p>A safe environment not only protects our employees, visitors, and contractors but also fosters a culture of trust and productivity.</p>
<p>The presence of weapons or firearms in the workplace can create unnecessary risks, cause fear or anxiety, and potentially escalate conflicts. To minimize these risks and ensure everyone feels secure, we have established this Weapons and Firearms Policy.</p>
<p>This policy is not intended to infringe on anyone''s rights but to balance those rights with our responsibility to provide a safe and professional environment. By adhering to these guidelines, we can collectively uphold the safety and well-being of everyone at IAT.</p>', 22, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms on Company Premises', 'weapons-firearms-on-company-premises', '<h2>Weapons and Firearms on Company Premises</h2>
<p>Weapons and firearms on company premises are strictly prohibited at Innovative Air Technologies (IAT). This policy applies to all individuals, including employees, visitors, contractors, and vendors, irrespective of possessing a valid permit to carry such items. The safety and security of everyone within IAT facilities are paramount, and the prohibition of weapons and firearms helps maintain a secure environment for all.</p>
<h3>Facilities include, but are not limited to:</h3>
<ul>
<li>Office spaces</li>
<li>Production Area</li>
<li>Storage areas</li>
<li>Parking lots (outside of vehicles)</li>
</ul>
<p>As part of IAT''s commitment to ensuring a safe workplace, the company enforces a <strong>zero-tolerance policy</strong> regarding weapons and firearms. This means that any individual found in possession of such items on company premises will face immediate disciplinary action, which may include termination of employment or removal from the premises.</p>
<p>By strictly enforcing this policy, IAT aims to create a secure and conducive work environment for all individuals associated with the company.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Employee photo — re-upload via admin editor</figcaption></figure>', 23, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms in Vehicles', 'weapons-firearms-in-vehicles', '<h2>Weapons and Firearms in Vehicles</h2>
<p>Employees are permitted to store weapons and firearms in their personal vehicles, as long as they are lawfully owned and in compliance with state and federal laws. These items must be stored securely, out of sight, and locked inside the vehicle at all times.</p>
<p>Employees who choose to keep weapons or firearms in their vehicles are responsible for maintaining the safety and security of these items. This includes ensuring that the weapons are properly secured and inaccessible to unauthorized individuals. By following these guidelines, employees can help maintain a safe and secure work environment for themselves and their colleagues.</p>', 24, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms: Exceptions', 'weapons-firearms-exceptions', '<h2>Weapons and Firearms: Exceptions</h2>
<blockquote><p><strong>This policy does not apply to authorized law enforcement officers or security personnel acting in their official capacity.</strong></p></blockquote>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Law enforcement officers photo — re-upload via admin editor</figcaption></figure>', 25, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weapons and Firearms: Violations and Reporting', 'weapons-firearms-violations-and-reporting', '<h2>Weapons and Firearms: Violations and Reporting</h2>
<blockquote><p><strong>Any violation of the company''s policy at Innovative Air Technologies (IAT) is taken very seriously and may result in disciplinary action.</strong></p></blockquote>
<p>Employees are expected to adhere to all policies and procedures in place to maintain a safe and productive work environment. Violations can range from minor interactions to more serious offenses, and the appropriate action will be taken based on the severity of the violation.</p>
<p>When it comes to visitors, contractors, or vendors found in violation of IAT''s policies, swift action will be taken. Any individual found to be in violation will be immediately removed from the premises. Additionally, they may be barred from future access to IAT facilities depending on the nature of the violation. This strict enforcement ensures that all individuals on company premises are held accountable for following the established policies and guidelines.</p>
<p>Employees who become aware of weapons or firearms inside IAT facilities or observe unsafe behavior related to weapons should immediately report the situation to their manager or HR.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Weapons and Firearms Violations and Reporting video thumbnail — re-upload via admin editor</figcaption></figure>', 26, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Attendance Policy Overview', 'attendance-policy-overview', '<h2>Attendance Policy Overview</h2>
<blockquote><p><em>Just come to work and you''ll be fine!</em></p></blockquote>
<p>Kidding! You get some time to yourself... but that''s in the Leave section, this section is all about showing up!</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Show" meme — re-upload via admin editor</figcaption></figure>', 27, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'General Attendance', 'general-attendance', '<h2>General Attendance</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "You done messed up, A-A-Ron" meme — re-upload via admin editor</figcaption></figure>
<p>The company maintains normal working hours of 6:00am–5:00pm. Hourly employees are required to clock in and out upon arrival and when leaving the premises for non-work related activities and when leaving for the day.</p>
<p>Lunch is automatically accounted for from 12:00–1:00pm. Hours may vary depending on work location and job responsibilities. Supervisors will provide employees with their work schedule.</p>
<p>Should an employee have any questions regarding his/her work schedule, the employee should contact the supervisor.</p>
<p>The company does not tolerate absenteeism without excuse. Employees who will be late to or absent from work should notify a supervisor in advance, or as soon as possible in the event of an emergency.</p>
<blockquote><p><strong>Chronic absenteeism or tardiness may result in disciplinary action or termination.</strong></p></blockquote>
<p>Employees who need to leave early, for illness or otherwise, should inform a supervisor before departure. Unauthorized departures may result in disciplinary action.</p>', 28, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Tardiness', 'tardiness', '<h2>Tardiness</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: "Sorry I''m late but I got here as soon as I wanted to" meme — re-upload via admin editor</figcaption></figure>
<blockquote><p><strong><em>Employees are expected to arrive on time and ready for work.</em></strong></p></blockquote>
<p>An employee who arrives 5 minutes after their scheduled arrival time is considered tardy. The company recognizes that situations arise which hinder punctuality; regardless, excessive tardiness is prohibited, and may be subject to disciplinary action. More than 3 tardy occurrences per quarter is subject to evaluation.</p>', 29, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Breaks and Lunch', 'breaks-and-lunch', '<h2>Breaks and Lunch</h2>
<p>Employees are entitled to 10 minute breaks every two hours during the work day.</p>
<p>Lunch is for 1 hour each day.</p>
<h3>Break Times:</h3>
<ul>
<li>8:00 – 8:10</li>
<li>10:00 – 10:10</li>
<li>3:00 – 3:10</li>
</ul>
<h3>Lunch Time:</h3>
<ul>
<li>12:00 – 1:00</li>
</ul>
<blockquote><p><strong>Returning from Break or Lunch late will not be accepted. Be prompt.</strong></p></blockquote>', 30, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Personal Cell Phone Use', 'personal-cell-phone-use', '<h2>Personal Cell Phone Use</h2>
<p>When it comes to our attendance policy at Innovative Air Technologies, we have specific guidelines regarding personal cell phone use during work hours. It is important to note that personal phone use is prohibited in the factory while employees are on duty. This policy is in place to ensure that our employees remain focused on their tasks and maintain a safe working environment.</p>
<p>However, we understand the importance of staying connected, which is why employees are allowed to use their personal devices during designated breaks or lunch periods. This provides an opportunity for individuals to check their phones, make personal calls, or respond to messages without interfering with their work responsibilities.</p>
<p>For company-related tasks that require the use of a device or computer, Innovative Air Technologies will provide the necessary equipment. This ensures that employees have access to the tools they need to effectively perform their job duties without relying on personal devices.</p>
<p>In the event of an emergency during office hours, employees can rest assured that their family and friends can reach them by contacting the main office number at <strong>770-788-6744</strong>. This allows for efficient communication in urgent situations while maintaining a professional and organized approach to handling personal matters during work hours.</p>
<h3>Using your personal cell phone/device for IAT business is allowed:</h3>
<ul>
<li>During breaks or at lunch hour</li>
<li>To briefly check important IAT messages</li>
<li>To conduct company business (Supervisor Approval Required)</li>
<li>To make business calls</li>
</ul>
<h3>The following rules apply at all times for both company-issued and personal phones:</h3>
<ul>
<li>Company-issued phones are to be used for business purposes only.</li>
<li>The use of a phone for any reason while driving a company vehicle is prohibited</li>
<li>The download or upload of inappropriate, illegal, or obscene material through a corporate internet connection is prohibited</li>
<li>The use of a cell phone''s camera or microphone to record confidential information is strictly prohibited</li>
<li>Surfing the internet, texting, and talking on the phone should be restricted to IAT business only</li>
<li>Playing games on the cell phone during working hours is prohibited.</li>
</ul>', 31, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Leave Policy Overview', 'leave-policy-overview', '<h2>Leave Policy Overview</h2>
<blockquote><p><strong>Leave Policies are our way of giving you a high-five for managing work and life without missing a beat.</strong></p></blockquote>
<p>Our Leave Policies lay out all the options for taking a break, whether you need a sick day, some vacation time, or you''re welcoming a new family member.</p>
<p>Having these rules in black and white allows us to maintain a positive work environment. It means everyone knows where they stand, making it easier to plan who''s doing what and when.</p>
<p>Plus, it keeps things fair and square, so there''s no drama about who gets time off. In short, clear leave policies are all about keeping everyone happy and making sure the show goes on smoothly.</p>', 32, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Annual Time', 'annual-time', '<h2>Annual Time</h2>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Vacation photo — re-upload via admin editor</figcaption></figure>
<blockquote><p><em>We know you want time off... Here''s how you get it...</em></p></blockquote>
<p>If you''re with us full-time and on a permanent basis, you get to rack up some hours every month for Annual Leave. You can use these hours to take some paid time off. Just a heads up, though, this Annual Leave Time policy is only for the full-timers, not for our temporary role friends.</p>
<h3>Employees will start to earn on the anniversary of hire date:</h3>
<ul>
<li>&lt;1 year: 5 hrs/month = 60 hrs per year</li>
<li>1–4 years: 6.67 hrs/month = 80 hrs per year</li>
<li>5–9 years: 10 hrs/month = 120 hrs per year</li>
<li>10+ years: 13.34 hrs/month = 160 hrs per year</li>
</ul>
<h3>Just a heads up on how we''re handling vacations and time off:</h3>
<ul>
<li>Stacking vacations back-to-back is a no-go, let''s keep it spaced out.</li>
<li>We can''t have two folks from the same area off at the same time or taking consecutive weeks off. But hey, if you chat with your manager, there might be some wiggle room. Remember that Open Door Policy we talked about earlier?</li>
<li>Ran out of vacation time? No worries, you can dip into the negatives up to 40 hours. Just a heads up, if you decide to part ways with us and you''re in the red, we''ll need to settle that with your last paycheck.</li>
<li>Didn''t use all your hours? They''ll roll over to next year, up to 240 hours.</li>
<li>If you end up with more than 240 hours at the end of the year, we''ll pay out the extra.</li>
<li>When you want to use your Annual Time, just fill out the right <strong>Annual Time Request Form</strong> and get it to your supervisor for approval.</li>
<li>Planning a big getaway? Just make sure to get your request in at least 2 weeks ahead if it''s 30+ hours.</li>
<li>Need a shorter break? Those under 30 hours are up to your manager, so have a chat with them.</li>
</ul>
<blockquote><p><strong>Let''s all try to make this work smoothly. Thanks, team!</strong></p></blockquote>
<h3>Annual Time may be requested for the following reasons:</h3>
<ol>
<li>Personal Time Off</li>
<li>Vacation Time</li>
<li>Leave Early (a need arises)</li>
</ol>', 33, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'company-policies'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Annual Time Form', 'annual-time-form', '<h2>Annual Time Form</h2>
<blockquote><p><em>Taking some time off is pretty key at any workplace, right?</em></p></blockquote>
<p>At Innovative Air Technologies, we''ve got this annual time off request form that everyone needs to fill out when they want to take a break. It''s our way of keeping everything organized and making sure everyone''s schedules mesh well together.</p>
<p>If you''re scratching your head wondering how to tackle that form, don''t sweat it! Check out the super handy video right below that walks you through the whole process. It''s like having a buddy show you the ropes, making sure you get everything down pat so your time off request slides through without a hitch.</p>
<figure class="img-missing"><figcaption>📷 Image from Trainual: Annual Time Request Form video tutorial — re-upload via admin editor</figcaption></figure>
<p>Here''s the form link — be sure to bookmark it for easy access!</p>
<p><a href="https://www.dehumidifiers.com/annual-time-request">Annual Time Request Form | Dehumidifiers.com</a></p>
<blockquote><p>Employees may not take a day off that falls after or before a holiday. Employees may not take a day off to "make" 40 hrs. on a time card for the week.</p></blockquote>', 34, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
