INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why IAT Exists', 'why-iat-exists', '<h2>Why IAT Exists</h2><p>Innovative Air Technologies exists to solve problems and enrich lives through environmental control.</p><p>At the most basic level, we design and build systems that control moisture in environments where humidity can create serious issues. But the bigger picture is that what we do impacts real people, real industries, and real outcomes every day.</p><p>Our systems help:</p><ul><li>protect products</li><li>improve manufacturing processes</li><li>prevent corrosion and failure</li><li>maintain consistency in critical environments</li></ul><p>What makes IAT different is that we don''t just focus on the equipment — we focus on the impact the equipment has on the customer''s operation.</p><p>A recurring idea throughout IAT is:</p><blockquote><p>"We don''t just make dehumidifiers."</p></blockquote><p>We solve problems in environments where failure is expensive, dangerous, or disruptive.</p><p>That mindset applies to:</p><ul><li>the products we build</li><li>the way we serve customers</li><li>and the way we work internally as a team</li></ul>', 1, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Core Values &amp; Expectations', 'core-values-and-expectations', '<h2>Core Values &amp; Expectations</h2><p>At IAT, core values are not meant to be posters on a wall. They are expected to show up in daily work, decision-making, communication, and problem solving.</p><h3>Problem Solving</h3><p>One of the foundational expectations at IAT is:</p><blockquote><p>If you identify a problem, think about possible solutions.</p></blockquote><p>Employees are encouraged to take ownership and actively think through challenges instead of simply passing problems along.</p><p>A common phrase used internally is:</p><blockquote><p>"Bring three solutions."</p></blockquote><p>The goal is not perfection — the goal is developing a mindset that looks for ways to improve situations instead of waiting for someone else to fix them.</p><h3>Integrity</h3><p>Integrity means doing the right thing even when nobody is watching.</p><p>Customers trust IAT systems to support critical environments and operations. That trust only exists if employees consistently:</p><ul><li>communicate honestly</li><li>take responsibility</li><li>and maintain high standards in their work</li></ul><h3>Team Mindset</h3><p>IAT operates with the understanding that everyone contributes to the success of the company.</p><p>Whether someone works in:</p><ul><li>engineering</li><li>manufacturing</li><li>service</li><li>sales</li><li>or administration</li></ul><p>their work impacts the final customer experience.</p><p>The expectation is that employees work together, support each other, and understand that small decisions can affect the larger outcome.</p><h3>Continuous Improvement</h3><p>Innovation at IAT is not limited to management or engineering teams.</p><p>Employees at every level are encouraged to ask:</p><blockquote><p>"Wouldn''t it be cool if..."</p></blockquote><p>Many improvements start from people noticing inefficiencies, frustrations, or opportunities on the floor and speaking up about them.</p><p>Small improvements made consistently create long-term success.</p>', 2, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What Makes IAT Different', 'what-makes-iat-different', '<h2>What Makes IAT Different</h2><p>Many companies manufacture products.</p><p>IAT focuses on understanding the environments and problems behind those products.</p><p>What makes IAT different is the combination of:</p><ul><li>technical knowledge</li><li>problem solving</li><li>customer understanding</li><li>and company culture</li></ul><h3>Real-World Impact</h3><p>The systems built at IAT support environments in industries such as:</p><ul><li>food processing</li><li>pharmaceuticals</li><li>aerospace</li><li>sports facilities</li><li>data centers</li><li>manufacturing</li><li>research laboratories</li></ul><p>In many cases, humidity control directly affects:</p><ul><li>product quality</li><li>equipment reliability</li><li>manufacturing consistency</li><li>and operational uptime</li></ul><p>Employees are encouraged to understand the bigger picture behind the systems they build and support.</p><h3>Details Matter</h3><p>Small details can have major consequences in environmental control systems.</p><p>Examples include:</p><ul><li>air leaks</li><li>improper sealing</li><li>incorrect airflow</li><li>contamination</li><li>poor organization</li><li>or inconsistent assembly quality</li></ul><p>Because of this, attention to detail is an important part of IAT''s culture.</p><h3>Cleanliness &amp; Organization</h3><p>A clean and organized environment reflects professionalism, pride, and quality.</p><p>Customers often associate:</p><ul><li>cleanliness</li><li>organization</li><li>and consistency</li></ul><p>with the reliability of the product itself.</p><p>Maintaining an organized workspace is part of maintaining high standards.</p><h3>Thinking Beyond Your Role</h3><p>Employees at IAT are encouraged to understand how their work impacts:</p><ul><li>the customer</li><li>the company</li><li>and the final application</li></ul><p>A person assembling components is not "just assembling parts." They may be supporting:</p><ul><li>a manufacturing line</li><li>a food facility</li><li>a data center</li><li>or another mission-critical environment</li></ul><p>Understanding that larger impact helps reinforce the importance of quality, consistency, and accountability throughout the company.</p>', 3, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'We Don''t "Just Make Dehumidifiers"', 'we-dont-just-make-dehumidifiers', '<h2>We Don''t "Just Make Dehumidifiers"</h2><p><em>Understanding What We Actually Do</em></p><p>One of the most important things to understand at IAT is that we do much more than simply manufacture dehumidifiers.</p><p>What we actually do is control environments where moisture can create serious problems.</p><p>Humidity affects:</p><ul><li>manufacturing processes</li><li>product quality</li><li>equipment reliability</li><li>storage conditions</li><li>and operational performance</li></ul><p>In many applications, moisture is not just an inconvenience — it can create:</p><ul><li>corrosion</li><li>condensation</li><li>contamination</li><li>equipment failure</li><li>or production downtime</li></ul><p>IAT systems are designed to prevent those issues before they happen.</p><p>That is why a common phrase at IAT is:</p><blockquote><p>"We solve problems."</p></blockquote><p>The equipment itself is only part of the solution. The larger goal is helping customers maintain stable, reliable, and controlled environments.</p><h3>Environmental Control vs Comfort Cooling</h3><p>Traditional HVAC systems are often designed for comfort:</p><ul><li>cooling buildings</li><li>heating spaces</li><li>maintaining basic indoor conditions</li></ul><p>IAT systems are often designed for process control instead.</p><p>That means customers are focused on:</p><ul><li>maintaining a specific humidity level</li><li>protecting products</li><li>preventing moisture issues</li><li>or meeting manufacturing requirements</li></ul><p>In many cases, the customer cares more about moisture control than temperature alone.</p><h3>Failure Isn''t Always Obvious</h3><p>One of the challenges with humidity control is that people often do not notice the importance of the system until something goes wrong.</p><p>For example:</p><ul><li>an ice rink may begin having ice quality problems</li><li>food products may clump or spoil</li><li>electronics may fail</li><li>metal components may corrode</li><li>powders may become unusable</li></ul><p>Many customers rely on environmental control systems to keep operations functioning properly every day.</p>', 4, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Industries We Serve', 'industries-we-serve', '<h2>Industries We Serve</h2><p>IAT equipment supports a wide range of industries and applications.</p><p>Although the environments may look very different, the common factor is that moisture control is critical to the customer''s process.</p><h3>Food Processing</h3><p>Many food ingredients are highly sensitive to moisture.</p><p>Products such as:</p><ul><li>salt</li><li>sugar</li><li>flour</li><li>powders</li><li>cereals</li><li>and dried mixes</li></ul><p>can clump, cake, or become difficult to process if humidity is not controlled.</p><p>Environmental control helps maintain:</p><ul><li>product consistency</li><li>manufacturing efficiency</li><li>storage quality</li></ul><h3>Pharmaceuticals</h3><p>Pharmaceutical manufacturing often requires tightly controlled humidity levels.</p><p>Moisture can affect:</p><ul><li>powders</li><li>tablets</li><li>coatings</li><li>and manufacturing consistency</li></ul><p>Humidity control helps maintain product quality and repeatability during production.</p><h3>Data Centers &amp; Electronics</h3><p>Moisture and electronics are a poor combination.</p><p>Environmental control systems help reduce the risk of:</p><ul><li>condensation</li><li>corrosion</li><li>electrical issues</li><li>and equipment failure</li></ul><p>Reliable environmental conditions are important for maintaining critical digital infrastructure.</p><h3>Aerospace &amp; Defense</h3><p>Aerospace and defense environments often require strict environmental control for:</p><ul><li>testing</li><li>storage</li><li>manufacturing</li><li>and material protection</li></ul><p>Humidity can affect:</p><ul><li>electronics</li><li>specialty materials</li><li>coatings</li><li>and precision components</li></ul><h3>Sports &amp; Recreation</h3><p>Some sports facilities rely heavily on humidity control.</p><p>For example:</p><ul><li>ice rinks require controlled humidity to maintain ice quality</li><li>professional sports organizations store equipment in controlled environments for consistency</li></ul><p>Even small changes in humidity can affect performance and operation.</p><h3>Manufacturing &amp; Industrial Processes</h3><p>Many manufacturing environments rely on environmental control to:</p><ul><li>prevent corrosion</li><li>improve consistency</li><li>protect materials</li><li>and maintain product quality</li></ul><p>This includes industries such as:</p><ul><li>tire manufacturing</li><li>plastics</li><li>coatings</li><li>automotive</li><li>and specialty manufacturing</li></ul><h3>Research &amp; Storage</h3><p>Research facilities and long-term storage environments often require stable humidity conditions to protect sensitive materials.</p><p>This can include:</p><ul><li>laboratories</li><li>museums</li><li>archives</li><li>seed storage</li><li>and preservation facilities</li></ul>', 5, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Real-World Impact Stories', 'real-world-impact-stories', '<h2>Real-World Impact Stories</h2><p>One of the best ways to understand IAT''s work is through real-world applications.</p><p>These examples show how environmental control affects everyday operations across many industries.</p><h3>Ice Rinks</h3><p>Ice rinks rely heavily on humidity control.</p><p>If humidity rises too high:</p><ul><li>condensation can form</li><li>visibility can decrease</li><li>and ice conditions can deteriorate</li></ul><p>In some cases, the entire environment can become difficult to maintain properly without dehumidification.</p><p>This is an example of how environmental control directly affects facility performance.</p><h3>Professional Baseball</h3><p>Professional baseball organizations store baseballs in controlled humidity environments.</p><p>Changes in moisture levels can affect:</p><ul><li>ball performance</li><li>consistency</li><li>and storage conditions</li></ul><p>Controlled environments help maintain repeatable conditions across different climates and locations.</p><h3>Air Force Base &amp; Aerospace Applications</h3><p>Environmental control systems are also used in aerospace-related applications.</p><p>Humidity can affect:</p><ul><li>specialty materials</li><li>sensitive finishes</li><li>electronics</li><li>and long-term equipment reliability</li></ul><p>Controlled environments help protect sensitive components and maintain stable conditions.</p><h3>Tire Manufacturing</h3><p>Modern tire manufacturing uses materials and mold components that can be sensitive to moisture.</p><p>If humidity is not properly controlled:</p><ul><li>corrosion can occur</li><li>manufacturing quality can decrease</li><li>and long-term mold reliability can be affected</li></ul><p>Environmental control helps support product consistency and safety.</p><h3>Data Centers</h3><p>Data centers rely on controlled environments to protect equipment and maintain uptime.</p><p>Moisture-related issues can create serious problems for:</p><ul><li>electronics</li><li>cooling systems</li><li>and infrastructure reliability</li></ul><p>Environmental control helps support stable operation of critical systems.</p><h3>Seed Preservation &amp; Long-Term Storage</h3><p>Certain facilities store seeds and sensitive materials in controlled environments for long-term preservation.</p><p>Humidity control helps prevent:</p><ul><li>moisture damage</li><li>deterioration</li><li>and unwanted biological activity</li></ul><p>These environments are designed to protect materials over long periods of time.</p><h3>The Bigger Picture</h3><p>A recurring theme at IAT is understanding the larger impact of the work being done.</p><p>Employees are encouraged to think beyond the equipment itself and understand:</p><ul><li>where the systems go</li><li>why they matter</li><li>and how they support the customer''s operation</li></ul><p>That perspective helps reinforce:</p><ul><li>quality</li><li>accountability</li><li>attention to detail</li><li>and pride of the work being performed</li></ul>', 6, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why Humidity Matters', 'why-humidity-matters', '<h2>Why Humidity Matters</h2><p><em>Dehumidification Fundamentals</em></p><p>Humidity is the amount of moisture present in the air.</p><p>Although moisture is a natural presence in every environment, too much humidity can create major problems in manufacturing, storage, processing, and environmental control applications.</p><p>At IAT, understanding humidity is one of the foundational concepts behind everything we do.</p><h3>Moisture Creates Problems</h3><p>Excess moisture can affect:</p><ul><li>product quality</li><li>manufacturing consistency</li><li>equipment reliability</li><li>storage conditions</li><li>and overall system performance</li></ul><p>Some common moisture-related problems include:</p><ul><li>corrosion and rust</li><li>condensation</li><li>mold or biological growth</li><li>product clumping</li><li>reduced process efficiency</li><li>electrical issues</li><li>and material degradation</li></ul><p>In many industries, even small humidity changes can create significant operational issues.</p><h3>Real-World Examples</h3><p>Humidity affects many products and processes people use every day.</p><p>Examples include:</p><ul><li>salt clumping in food processing</li><li>powder drink mixes absorbing moisture</li><li>electronics failing due to condensation</li><li>metal corroding in manufacturing</li><li>baseballs stored at controlled humidity</li><li>ice rink performance being affected by moisture in the air</li></ul><p>These examples help show that humidity control is not just about comfort — it directly impacts quality and performance.</p><h3>Humidity &amp; Air</h3><p>One of the most important concepts to understand is: warm air can hold more moisture than cold air.</p><p>As air heats up:</p><ul><li>it expands</li><li>and its moisture-holding capacity increases</li></ul><p>As air cools down:</p><ul><li>it contracts</li><li>and it can hold less moisture</li></ul><p>This relationship between air temperature and moisture is the foundation of psychrometrics and dehumidification.</p>', 7, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Relative Humidity Explained', 'relative-humidity-explained', '<h2>Relative Humidity Explained</h2><p>Relative humidity is one of the most common measurements used in environmental control.</p><p>Relative humidity compares:</p><blockquote><p>how much moisture is currently in the air<br>to<br>how much moisture the air could hold at that temperature</p></blockquote><p>It is expressed as a percentage.</p><h3>Understanding Relative Humidity</h3><p>Examples:</p><ul><li>50% relative humidity means the air is holding about half of the moisture it could potentially hold at that temperature</li><li>100% relative humidity means the air is fully saturated</li></ul><p>When air reaches saturation:</p><ul><li>it cannot hold additional moisture</li><li>and condensation can begin forming</li></ul><h3>Why Temperature Matters</h3><p>Relative humidity changes when temperature changes.</p><p>For example:</p><ul><li>warm air can hold much more moisture</li><li>cool air can hold much less moisture</li></ul><p>This is why:</p><ul><li>summer air often feels humid</li><li>winter air often feels dry</li></ul><p>Even if the amount of moisture in the air stays the same, relative humidity changes as temperature changes.</p><h3>Common Misconceptions</h3><p>People often assume: "50% humidity doesn''t sound very humid."</p><p>However, at high temperatures, 50–60% humidity can represent a very large amount of moisture in the air.</p><p>That is why hot summer days can feel extremely humid even when the relative humidity percentage does not appear very high.</p>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Dew Point, Condensation &amp; Moisture', 'dew-point-condensation-and-moisture', '<h2>Dew Point, Condensation &amp; Moisture</h2><p>Dew point is the temperature at which air becomes fully saturated and moisture begins to condense into liquid water.</p><p>The concept is important because it explains:</p><ul><li>condensation</li><li>fog</li><li>sweating pipes</li><li>and moisture buildup on surfaces</li></ul><h3>What Happens During Condensation</h3><p>As air cools:</p><ul><li>it loses its ability to hold moisture</li></ul><p>Once the air reaches 100% relative humidity:</p><ul><li>excess moisture begins leaving the air as liquid water</li></ul><p>This is called condensation.</p><p>Examples include:</p><ul><li>water forming on cold pipes</li><li>vehicle air conditioners dripping water</li><li>fog forming outdoors</li><li>moisture collecting on cold surfaces</li></ul><h3>Cooling Air Removes Moisture</h3><p>Traditional cooling systems remove moisture by:</p><ul><li>cooling air below its dew point</li><li>causing moisture to condense out</li></ul><p>This is why air conditioning systems produce water during operation.</p><p>However, cooling systems have limitations:</p><ul><li>temperatures approaching freezing</li><li>coils can ice up</li><li>and performance becomes limited</li></ul><p>This means refrigeration systems alone cannot always achieve extremely low humidity conditions efficiently.</p><h3>Real-World Example</h3><p>A common example is a cold drink sitting outside on a hot day.</p><p>The moisture forming on the outside of the cup is not leaking from inside the cup. Instead:</p><ul><li>warm humid air contacts the cold surface</li><li>the air cools below its dew point</li><li>and moisture condenses into liquid water</li></ul>', 9, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Understanding Psychrometrics', 'understanding-psychrometrics', '<h2>Understanding Psychrometrics</h2><p>Psychrometrics is the study of the relationship between:</p><ul><li>air</li><li>temperature</li><li>and moisture</li></ul><p>The psychrometric chart is a tool used to visualize and understand those relationships.</p><p>Although it may appear complicated at first, the chart is simply showing how temperature and moisture interact.</p><h3>What the Psychrometric Chart Shows</h3><p>The chart helps visualize:</p><ul><li>dry bulb temperature</li><li>relative humidity</li><li>dew point</li><li>moisture content</li><li>and other air properties</li></ul><p>At a basic level, the chart is simply a map of temperature and moisture conditions.</p><h3>Dry Bulb Temperature</h3><p>Dry bulb temperature is the standard air temperature people normally reference.</p><p>This is:</p><ul><li>outdoor temperature</li><li>room temperature</li><li>or the temperature shown on a standard thermometer</li></ul><p>At IAT, temperatures are typically referenced in Fahrenheit.</p><h3>Moisture Content</h3><p>Moisture content refers to the actual amount of moisture present in the air.</p><p>One common measurement used is: grains of moisture per pound of dry air.</p><p>Unlike relative humidity, moisture content represents the actual amount of water vapor present regardless of temperature.</p><h3>Basic Chart Movement</h3><p>Understanding movement on the psychrometric chart is helpful for understanding environmental control.</p><p>General rules:</p><ul><li>moving left = cooling air</li><li>moving right = heating air</li><li>moving up = adding moisture</li><li>moving down = removing moisture</li></ul><p>These concepts help explain what happens inside:</p><ul><li>cooling systems</li><li>dehumidifiers</li><li>and environmental control equipment</li></ul><h3>Why Psychrometrics Matters</h3><p>Psychrometrics helps explain:</p><ul><li>how dehumidification works</li><li>why condensation occurs</li><li>how environmental conditions change</li><li>and how systems are designed to control moisture</li></ul><p>Understanding these relationships is foundational to understanding IAT equipment and applications.</p>', 10, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Desiccant?', 'what-is-desiccant', '<h2>What is Desiccant?</h2><p><em>Desiccant Dehumidification Basics</em></p><p>A desiccant is a material that attracts and holds moisture from the air.</p><p>At IAT, the most common desiccant material used is silica gel.</p><p>Although silica gel is often associated with the small packets found in product packaging, industrial desiccant systems use the same basic concept on a much larger scale.</p><h3>Understanding the Sponge Analogy</h3><p>One of the simplest ways to understand desiccant dehumidification is with a sponge analogy.</p><p>Think about a dry sponge:</p><ul><li>it absorbs water slowly</li></ul><p>Eventually:</p><ul><li>the sponge becomes saturated</li><li>and can no longer absorb additional moisture</li></ul><p>To reuse the sponge:</p><ul><li>the water must be squeezed out</li></ul><p>Desiccant systems work in a very similar way.</p><p>The desiccant absorbs moisture from the air, and then heat is used to remove that moisture so the process can continue repeatedly.</p><h3>Adsorption vs. Absorption</h3><p>Desiccant systems use a process called adsorption:</p><ul><li>Absorption means moisture soaks into a material</li><li>Adsorption means moisture attaches to the surface of the material</li></ul><p>Silica gel attracts water vapor and holds it on its surface until heat is applied to release it.</p><h3>Why Desiccants Matter</h3><p>Desiccant systems are useful because they can remove moisture beyond the limits of standard cooling systems.</p><p>They are especially effective in:</p><ul><li>low-humidity environments</li><li>cold conditions</li><li>and applications requiring precise moisture control</li></ul>', 11, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How a Desiccant Wheel Works', 'how-a-desiccant-wheel-works', '<h2>How a Desiccant Wheel Works</h2><p>The desiccant wheel is the core component of most IAT dehumidification systems.</p><p>The wheel is coated with desiccant material and continuously rotates during operation.</p><p>As the wheel rotates:</p><ul><li>one side absorbs moisture from the process air</li><li>while the other side is regenerated using heated air</li></ul><p>This creates a continuous cycle of moisture removal.</p><h3>The Two Air Streams</h3><p>A desiccant system typically has two separate air streams:</p><h3>Process Air</h3><p>The process air stream is:</p><ul><li>the primary air stream</li><li>and the dry air delivered to the customer''s space</li></ul><p>This is the air stream the customer cares about most.</p><h3>Reactivation Air</h3><p>The reactivation air stream is:</p><ul><li>heated air used to remove moisture from the desiccant wheel</li></ul><p>This heated air:</p><ul><li>draws moisture out of the desiccant</li><li>and carries that moisture out of the system</li></ul><p>The reactivation air stream is often referred to as: <em>"react air."</em></p><h3>Continuous Rotation</h3><p>The wheel rotates continuously so the system can:</p><ul><li>absorb moisture</li><li>regenerate the desiccant</li><li>and continue operating without stopping</li></ul><p>If the wheel stops rotating:</p><ul><li>the desiccant quickly becomes saturated</li><li>and moisture removal performance drops significantly</li></ul>', 12, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Cooling vs. Desiccant Dehumidification', 'cooling-vs-desiccant-dehumidification', '<h2>Cooling vs. Desiccant Dehumidification</h2><p>Traditional cooling systems remove moisture by cooling air below its dew point.</p><p>This works well for many comfort cooling applications, but it has limitations:</p><h3>Limits of Cooling Systems</h3><p>As cooling systems continue lowering air temperatures:</p><ul><li>condensation forms</li><li>and moisture is removed</li></ul><p>However, eventually:</p><ul><li>temperatures approach freezing</li><li>coils can ice up</li><li>and performance becomes limited</li></ul><p>This means refrigeration systems alone cannot always achieve extremely low humidity conditions efficiently.</p><h3>Why Desiccant Systems Exist</h3><p>Desiccant systems are designed to remove moisture without relying entirely on cooling.</p><p>This allows:</p><ul><li>lower humidity levels</li><li>more precise control</li><li>and operation in environments where refrigeration alone is not practical</li></ul><p>Desiccant systems are often used in:</p><ul><li>fabrication</li><li>wiring</li><li>engineering</li><li>assembly</li><li>controls</li><li>service</li><li>or logistics</li></ul><p>Their work contributes to the customer''s final experience.</p><p>A successful project depends on many people working together with shared standards and expectations.</p>', 13, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Understanding the Responsibility of the Work', 'understanding-the-responsibility-of-the-work', '<h2>Understanding the Responsibility of the Work</h2><p>One of the recurring ideas throughout training is:</p><blockquote><p>These systems often support mission-critical environments.</p></blockquote><p>Customers may rely on IAT systems to:</p><ul><li>maintain manufacturing</li><li>protect products</li><li>support research</li><li>preserve materials</li><li>or maintain environmental stability</li></ul><p>Because of this, reliability and consistency matter.</p><h3>The Work Has Real-World Impact</h3><p>Employees are encouraged to understand that the systems they build may support:</p><ul><li>food production</li><li>pharmaceutical manufacturing</li><li>aerospace applications</li><li>data centers</li><li>research facilities</li><li>and other critical environments</li></ul><p>Understanding the larger impact behind the work helps reinforce:</p><ul><li>accountability</li><li>attention to detail</li><li>and pride in craftsmanship</li></ul><h3>Building More Than Equipment</h3><p>At IAT, employees are not simply assembling parts.</p><p>They are contributing to systems that help customers:</p><ul><li>solve problems</li><li>maintain operations</li><li>and protect important processes</li></ul><p>That larger perspective is an important part of IAT''s culture and mindset.</p>', 14, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'The ''3 Solutions'' Rule', 'the-3-solutions-rule', '<h2>The ''3 Solutions'' Rule</h2><p><em>Problem Solving &amp; Innovation at IAT</em></p><p>One of the recurring expectations at IAT is:</p><blockquote><p>Don''t just identify problems — think about solutions.</p></blockquote><p>Anyone can point out an issue. The real value comes from thinking critically about how to improve the situation.</p><p>A common phrase used internally is:</p><blockquote><p>"Bring three solutions."</p></blockquote><p>The purpose of this mindset is not to force perfect answers. The goal is to encourage:</p><ul><li>ownership</li><li>critical thinking</li><li>initiative</li><li>and problem-solving habits</li></ul><h3>Why This Matters</h3><p>Environmental control systems are complex.</p><p>Problems can involve:</p><ul><li>airflow</li><li>controls</li><li>heat</li><li>moisture</li><li>assembly</li><li>installation</li><li>or customer applications</li></ul><p>Employees who actively think through possible solutions help:</p><ul><li>improve efficiency</li><li>reduce mistakes</li><li>speed up troubleshooting</li><li>and strengthen teamwork</li></ul><h3>Thinking Beyond "That''s Not My Job"</h3><p>At IAT, employees are encouraged to think beyond their individual team or department.</p><p>A systems-thinking mindset means understanding:</p><ul><li>how your work affects others</li><li>how small issues impact larger systems</li><li>and how solving problems early benefits the entire project</li></ul><p>The goal is to create a culture where people actively contribute ideas and improvements instead of simply completing assigned tasks.</p>', 15, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '''Wouldn''t It Be Cool if...''', 'wouldnt-it-be-cool-if', '<h2>''Wouldn''t It Be Cool if...''</h2><p>Innovation at IAT does not only come from management or engineering leadership.</p><p>Many improvements begin with simple observations or questions from employees throughout the company.</p><p>One phrase repeatedly used during training is:</p><blockquote><p>"Wouldn''t it be cool if..."</p></blockquote><p>This mindset encourages curiosity, creativity, and continuous improvement.</p><h3>Innovation Starts with Observation</h3><p>Employees working closest to the product or process often notice:</p><ul><li>inefficiencies</li><li>frustrations</li><li>recurring issues</li><li>or opportunities for improvement</li></ul><p>Small ideas can lead to:</p><ul><li>better manufacturing methods</li><li>easier serviceability</li><li>improved airflow</li><li>cleaner layouts</li><li>or more efficient processes</li></ul><h3>Continuous Improvement</h3><p>Continuous improvement does not always require major redesigns.</p><p>Small improvements made consistently over time create significant long-term results.</p><p>Examples include:</p><ul><li>reducing unnecessary movement</li><li>improving organization</li><li>simplifying assembly</li><li>improving access to components</li><li>or identifying repeat problems</li></ul><p>The goal is to create a culture where employees actively look for ways to improve systems and processes.</p><h3>No One Understands Everything Alone</h3><p>Environmental control systems involve many disciplines:</p><ul><li>engineering</li><li>manufacturing</li><li>controls</li><li>service</li><li>installation</li><li>and customer applications</li></ul><p>Good ideas can come from anywhere.</p><p>Employees are encouraged to:</p><ul><li>ask questions</li><li>share ideas</li><li>and collaborate with others to improve systems and processes</li></ul>', 16, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Thinking Like an Engineer', 'thinking-like-an-engineer', '<h2>Thinking Like an Engineer</h2><p>At IAT, employees are encouraged to develop an engineering mindset regardless of their role.</p><p>Thinking like an engineer means:</p><ul><li>understanding cause and effect</li><li>asking why problems happen</li><li>and considering how systems interact</li></ul><h3>Systems Thinking</h3><p>A major idea reinforced throughout training is:</p><blockquote><p>Everything affects everything else.</p></blockquote><p>Examples:</p><ul><li>airflow affects moisture removal</li><li>heat affects wheel regeneration</li><li>seals affect airflow balance</li><li>maintenance affects performance</li><li>assembly affects reliability</li></ul><p>Understanding how systems interact helps employees:</p><ul><li>troubleshoot more effectively</li><li>avoid repeated mistakes</li><li>and better understand customer applications</li></ul><h3>Cause &amp; Effect Thinking</h3><p>Environmental control systems depend heavily on details.</p><p>Small changes can create major performance differences.</p><p>Examples include:</p><ul><li>dirty filters reducing airflow</li><li>leaks contaminating dry air</li><li>incorrect seals reducing performance</li><li>or poor sealing affecting efficiency</li></ul><p>Employees are encouraged to think through:</p><ul><li>what changed</li><li>why it matters</li><li>and what effect it creates on the larger system</li></ul><h3>Learning Never Stops</h3><p>Environmental control and dehumidification involve ongoing learning.</p><p>As employees gain experience, they develop a deeper understanding of:</p><ul><li>airflow</li><li>humidity</li><li>troubleshooting</li><li>applications</li><li>and system performance</li></ul><p>Employees are encouraged to:</p><ul><li>ask questions</li><li>continue learning</li><li>and stay curious about how systems operate</li></ul>', 17, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Understanding the Bigger Mission', 'understanding-the-bigger-mission', '<h2>Understanding the Bigger Mission</h2><p>One of the most important themes throughout IAT training is: the work matters.</p><p>The systems built at IAT support environments where reliability, consistency, and moisture control are critical.</p><p>Employees are encouraged to understand that their work may help support:</p><ul><li>manufacturing facilities</li><li>food production</li><li>pharmaceuticals</li><li>aerospace applications</li><li>sports facilities</li><li>data centers</li><li>and research environments</li></ul><h3>More Than Equipment</h3><p>At IAT, the goal is not simply building machines.</p><p>The goal is:</p><ul><li>solving customer problems</li><li>protecting customer operations</li><li>improving reliability</li><li>and supporting critical environments</li></ul><p>Understanding that larger mission helps reinforce:</p><ul><li>accountability</li><li>craftsmanship</li><li>teamwork</li><li>and pride in the work</li></ul><h3>The IAT Mindset</h3><p>The IAT mindset combines:</p><ul><li>technical understanding</li><li>problem solving</li><li>continuous improvement</li><li>teamwork</li><li>and ownership</li></ul><p>Employees are encouraged to:</p><ul><li>think critically</li><li>ask questions</li><li>improve systems</li><li>and understand the larger impact of the work being done</li></ul><p>This mindset is a major part of what makes IAT different.</p>', 18, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'How Everything Connects', 'how-everything-connects', '<h2>How Everything Connects</h2><p><em>Bringing It All Together</em></p><p>Throughout this training, several major ideas have been repeated consistently:</p><ul><li>humidity affects real-world processes</li><li>environmental control depends on details</li><li>systems thinking matters</li><li>and the work being done at IAT has real impact</li></ul><p>Understanding dehumidification is not just about learning individual components or memorizing technical information.</p><p>The larger goal is understanding how:</p><ul><li>airflow</li><li>heat</li><li>moisture</li><li>controls</li><li>manufacturing</li><li>service</li><li>and customer applications</li></ul><p>all work together as part of a complete system.</p><h3>Environmental Controls is a System</h3><p>Every part of a dehumidification system affects overall performance.</p><p>Examples include:</p><ul><li>airflow affecting moisture removal</li><li>heat affecting wheel regeneration</li><li>sealing affecting system balance</li><li>maintenance affecting reliability</li><li>and assembly quality affecting long-term operation</li></ul><p>Because everything is connected, attention to detail is critical throughout:</p><ul><li>engineering</li><li>manufacturing</li><li>startup</li><li>service</li><li>and customer support</li></ul><h3>Technical Knowledge + Problem Solving</h3><p>At IAT, technical knowledge alone is not enough.</p><p>Employees are also encouraged to:</p><ul><li>think critically</li><li>solve problems</li><li>ask questions</li><li>and continuously improve processes</li></ul><p>The goal is not simply following instructions.</p><p>The goal is understanding:</p><ul><li>why systems work</li><li>why details matter</li><li>and how fine decisions affect the customer</li></ul>', 19, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'The Responsibility of What to Build', 'the-responsibility-of-what-to-build', '<h2>The Responsibility of What to Build</h2><p>A major theme throughout the training is understanding the responsibility behind the systems being built and supported.</p><p>IAT equipment is often used in environments where failure creates serious consequences.</p><p>These systems may support:</p><ul><li>food production</li><li>pharmaceuticals</li><li>aerospace</li><li>manufacturing</li><li>data centers</li><li>research facilities</li><li>and other critical operations</li></ul><h3>Reliability Matters</h3><p>Customers rely on IAT systems to:</p><ul><li>maintain environmental conditions</li><li>protect products</li><li>support manufacturing</li><li>and reduce downtime</li></ul><p>In many cases, the customer may not think about the dehumidification system until something stops working.</p><p>That is why:</p><ul><li>consistency</li><li>reliability</li><li>quality</li><li>and attention to detail</li></ul><p>are so important.</p><h3>Small Details Affect Big Outcomes</h3><p>Throughout the training, one message appears repeatedly: small problems can create major consequences.</p><p>Examples include:</p><ul><li>air leaks</li><li>poor sealing</li><li>incorrect airflow</li><li>contamination</li><li>or improper maintenance</li></ul><p>Because of this, every role within the company contributes to the final performance of the system.</p>', 20, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is Expected Moving Forward', 'what-is-expected-moving-forward', '<h2>What is Expected Moving Forward</h2><p>The purpose of this training is not only to introduce dehumidification concepts.</p><p>It is also intended to help employees understand:</p><ul><li>how IAT thinks and works</li><li>how systems work</li><li>and why the work matters</li></ul><p>Employees are encouraged to continue developing:</p><ul><li>technical understanding</li><li>problem-solving skills</li><li>attention to detail</li><li>and systems-thinking habits</li></ul><h3>Expectations at IAT</h3><p>Employees are encouraged to:</p><ul><li>take ownership</li><li>think beyond individual tasks</li><li>ask questions</li><li>identify improvements</li><li>and contribute ideas</li></ul><p>The expectation is not perfection.</p><p>The expectation is continuous learning and continuous improvement.</p><h3>The Importance of Curiosity</h3><p>Environmental control systems are complex, and learning continues long after onboarding.</p><p>Employees are encouraged to stay curious about:</p><ul><li>how systems operate</li><li>why problems occur</li><li>and how processes can improve</li></ul><p>Questions, observations, and new ideas are important parts of growth and innovation.</p><h3>Building More Than Equipment</h3><p>At IAT, employees are not simply assembling machines.</p><p>They are helping build systems that:</p><ul><li>support customer operations</li><li>protect important processes</li><li>solve real-world problems</li><li>and maintain critical environments</li></ul><p>Understanding the larger impact behind the work helps reinforce:</p><ul><li>accountability</li><li>craftsmanship</li><li>teamwork</li><li>and pride in the final product</li></ul>', 21, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Final Takeaways', 'final-takeaways', '<h2>Final Takeaways</h2><p>The major ideas throughout this training can be summarized simply:</p><ul><li>Humidity matters</li><li>Details matter</li><li>Systems thinking matters</li><li>Problem solving matters</li><li>The work has real-world impact</li></ul><p>IAT combines:</p><ul><li>technical knowledge</li><li>engineering</li><li>manufacturing</li><li>customer understanding</li><li>and continuous improvement</li></ul><p>to solve environmental control challenges across many industries.</p><p>Employees who understand both:</p><ul><li>the technical side</li><li>and the larger purpose behind the work</li></ul><p>are better prepared to contribute to the success of:</p><ul><li>the customer</li><li>the company</li><li>and the team around them</li></ul><h3>Final Thought</h3><p>A recurring idea throughout this training is:</p><blockquote><p>"We don''t just make dehumidifiers."</p></blockquote><p>IAT exists to solve problems, support critical environments, and help customers maintain reliable operations.</p><p>Every employee plays a role in making that happen.</p>', 22, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'company' AND m.slug = 'iat'
ON CONFLICT (module_id, slug) DO NOTHING;

