SELECT m.id, 'Electrical Design Procedure – 002', 'electrical-design-procedure-002', '<h2>Electrical Design Procedure – 002</h2><p>This document defines the standardized procedure for transitioning engineered concepts into production-ready design packages. Its purpose is to ensure accuracy, consistency, and cross-functional alignment from initial project release through final build documentation.</p><ol><li><em>Purpose</em><ol type="a"><li>To show the production design phase process for IAT DH units.</li></ol></li><li><em>Scope</em><ol type="a"><li>Rotor Series and IDP Units.</li></ol></li><li><em>Responsibility</em><ol type="a"><li>Electrical Engineering</li></ol></li><li><em>References</em><ol type="a"><li>N/A</li></ol></li><li><em>Definitions</em><ol type="a"><li>IDP – Integrated Desiccant Product</li><li>LLI – Long-Lead Items</li><li>DH – Dehumidifier</li></ol></li><li><em>Safety</em><ol type="a"><li>N/A</li></ol></li><li><em>Procedure</em></li></ol><h3>Procedure Checklist</h3><ol><li><strong>Review the approved submittal package.</strong><ol type="a"><li>Review customer notes, if approved as noted.</li><li>Review deviations, if approved as noted.</li><li>Review Sales Order.</li><li>Review LLI cutsheets.</li></ol></li><li><strong>Review all project info for discrepancies.</strong><ol type="a"><li>If errors or discrepancies exist, contact source for clarification.</li><li>Once all project info is verified, continue to next step.</li></ol></li><li><strong>Open electrical submittal drawing in job folder.</strong><ol type="a"><li>Update revision number and file name to reflect new document.</li></ol></li><li><strong>Revise electrical drawing based on purchased components.</strong></li><li><strong>Finalize high voltage circuitry.</strong><ol type="a"><li>Confirm and review terminal numbering and color code for validity.</li><li>Confirm and review FLA of high voltage components.</li><li>Confirm and review overcurrent protection of high voltage components per UL 508A standard.</li><li>Confirm and review wire gauge size for high voltage components per UL 508A standard.</li></ol></li><li><strong>Update unit&apos;s FLA, MCA, and MOCP values.</strong></li><li><strong>Export PDF of finalized production level electrical drawings.</strong></li><li><strong>Confirm control enclosure size with electrical team lead.</strong></li><li><strong>Complete electrical BOM.</strong></li><li><strong>Release BOM and electrical drawing package to production.</strong></li><li><strong>Once unit moves past QA</strong><ol type="a"><li>Are there redlines from production?<ol><li>If yes, update the revision number and file name to reflect new document and apply changes.</li><li>If no, no changes required.</li></ol></li><li>Place as built drawing package into IOM folder in the job file.</li></ol></li></ol>', 68, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Electric Heater Sizing and Selection', 'electric-heater-sizing-and-selection', '<h2>Electric Heater Sizing and Selection</h2><h3>Purpose</h3><p>This guide explains how to size and stage electric heaters for a project while following standard heater construction limits and electrical design requirements.</p><h3>Why this matters</h3><p>Electric heaters are not built to every exact kW value shown in a flow diagram or specification. Heater sizing must be adjusted to match available heater increments, maintain proper staging balance, and stay within allowable amperage per stage.</p><h3>Key Rules for Electric Heater Selection</h3><h3>1. Heater increments</h3><p>Electric heaters are built in the following increments:</p><ul><li>12.5 kW</li><li>6.25 kW</li></ul><p>Because of this, the exact required load often cannot be matched exactly and must be rounded to the nearest practical heater combination.</p><h3>2. Round heater load appropriately</h3><p>If the specified load is not an exact match to available increments, round to a buildable value using 12.5 kW and 6.25 kW combinations.</p><p>In general:</p><ul><li>Do <strong>not</strong> size to an impossible exact value</li><li>Use standard heater increments</li><li>Round in a way that supports practical staging</li></ul><h3>3. Maximum amps per stage</h3><p>The maximum current per stage should <strong>not exceed 48 amps</strong>.</p><p>This is done to remain within a standard <strong>60A branch circuit</strong> per <strong>NEC continuous load requirements</strong>.</p><h3>4. 480V stage limit</h3><p>For a <strong>480V system</strong>, stage size should typically <strong>not exceed 37.5 kW per stage</strong>, since this places the stage near the upper amp limit.</p><h3>5. Keep stages balanced</h3><p>Stages should be distributed as evenly as possible.</p><p>Avoid poor load distribution such as:</p><ul><li>Stage 1: 37.5 kW</li><li>Stage 2: 6.25 kW</li></ul><p>Prefer more balanced staging such as:</p><ul><li>Stage 1: 25 kW</li><li>Stage 2: 18.75 kW</li></ul><p>Balanced staging improves system performance and creates a more practical design.</p><h3>6. SCR assignment</h3><ul><li><strong>Stage 1 always includes the SCR</strong></li><li><strong>All additional stages do not include the SCR</strong></li></ul><p>This rule should always be followed when laying out heater stages.</p><h3>Step-by-Step Process for Electric Heater Sizing and Selection</h3><h3>Step 1: Identify the required heater load</h3><p>Start with the heater load shown on the project documents, flow diagram, or specifications.</p><p>Example: Required load = <strong>64.6 kW</strong></p><h3>Step 2: Check whether the load can be built exactly</h3><p>Compare the required kW to standard heater increments (12.5 kW and 6.25 kW). If the load cannot be matched exactly, move to the next step.</p><p>Example: 64.6 kW cannot be built exactly</p><h3>Step 3: Round to the nearest practical buildable heater value</h3><p>Round the load to a value that can be built using standard increments.</p><p>For this project: Required load = 64.6 kW &rarr; Selected load = <strong>68.75 kW</strong></p><p>This is made up of: Five 12.5 kW heaters + One 6.25 kW heater</p><p>Calculation: 5 &times; 12.5 = 62.5 kW + 1 &times; 6.25 = 6.25 kW = Total = <strong>68.75 kW</strong></p><h3>Step 4: Determine the number of stages needed</h3><p>Break the total heater load into stages while following these rules:</p><ul><li>No stage should exceed <strong>48A</strong></li><li>On <strong>480V systems</strong>, do not typically exceed <strong>37.5 kW per stage</strong></li><li>Keep the stages as balanced as possible</li></ul><h3>Step 5: Assign Stage 1</h3><p>Stage 1 should be the first stage selected, and it must include the SCR.</p><p>For this project: Stage 1 = 37.5 kW, Stage 1 is SCR controlled</p><h3>Step 6: Assign the remaining load to Stage 2</h3><p>After assigning Stage 1, place the remaining heater load into Stage 2.</p><p>Calculation: Total heater load = 68.75 kW, Stage 1 = 37.5 kW, Remaining load = <strong>31.25 kW</strong> &rarr; Stage 2 = 31.25 kW. Stage 2 does <strong>not</strong> include an SCR.</p><h3>Step 7: Review stage balance</h3><p>Confirm the stages are reasonably balanced. For this project: Stage 1 = 37.5 kW, Stage 2 = 31.25 kW. This is acceptable because both stages are substantial and the load is distributed more evenly than a heavily unbalanced arrangement.</p><h3>Step 8: Finalize the heater selection</h3><p>Document the final heater total and stage breakdown clearly in the project file, quote, or submittal.</p><p><strong>Final selection for this project:</strong></p><ul><li>Total Heater Load: 68.75 kW</li><li>Stage 1: 37.5 kW (SCR controlled)</li><li>Stage 2: 31.25 kW</li></ul><h3>Worked Example</h3><p><strong>Project requirement:</strong> The project calls for 64.6 kW.</p><p><strong>Selected heater load:</strong> Since 64.6 kW cannot be built exactly, round up to 68.75 kW.</p><p><strong>Heater makeup:</strong></p><ul><li>5 &times; 12.5 kW</li><li>1 &times; 6.25 kW</li></ul><p><strong>Staging:</strong></p><ul><li>Stage 1: 37.5 kW (SCR controlled)</li><li>Stage 2: 31.25 kW</li></ul><p><strong>Notes:</strong></p><ul><li>Stage 1 includes the SCR</li><li>Stage 2 does not include the SCR</li><li>Stage 1 does not exceed the practical 480V limit</li><li>The stages are reasonably balanced</li></ul><h3>Quick Reference Rules</h3><ul><li>Use only <strong>12.5 kW</strong> and <strong>6.25 kW</strong> heater increments</li><li>Round to a buildable heater size</li><li>Keep stage amps at <strong>48A or below</strong></li><li>On <strong>480V</strong>, do not typically exceed <strong>37.5 kW per stage</strong></li><li>Balance stages whenever possible</li><li><strong>Stage 1 always includes the SCR</strong></li><li>Additional stages do <strong>not</strong> include the SCR</li></ul><h3>Common Mistakes to Avoid</h3><p>Do not:</p><ul><li>Try to match odd heater loads exactly when they cannot be built</li><li>Exceed the maximum practical stage size</li><li>Create highly unbalanced stages when a better distribution is possible</li><li>Add an SCR to stages beyond Stage 1</li><li>Ignore branch circuit amp limitations</li></ul><h3>Recommended Workflow for Every Project</h3><ol><li>Review the specified heater load.</li><li>Convert the required load to a buildable value using 12.5 kW and 6.25 kW increments.</li><li>Round appropriately.</li><li>Divide the total load into practical stages.</li><li>Confirm no stage exceeds 48A.</li><li>On 480V systems, keep stages at or below 37.5 kW where possible.</li><li>Balance stage loads as evenly as practical.</li><li>Assign the SCR to Stage 1 only.</li><li>Document the final heater total and stage breakdown.</li></ol>', 69, TRUE, 8
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
ON CONFLICT (module_id, slug) DO NOTHING;
