SELECT m.id, 'How to Find Dewpoint to Determine Temp and Humidity Sensor Required', 'how-to-find-dewpoint-sensor-selection', '<h2>How to Find Dewpoint to Determine Temp &amp; Humidity Sensor Required</h2><p>Check if dewpoint process:</p><p>Go to IAT Calculator App: <a href="https://iatcalc.dehumidifiers.com/CalculatorApp">https://iatcalc.dehumidifiers.com/CalculatorApp</a></p><p>Select the Psychrometric button.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: IAT Calculator App home screen showing the Psychrometric button highlighted among other calculator options including Moisture Removal, Air Mixing, Velocity/CFM, Btuh &amp; Kwh, Coil Widths-CV, React Heat, Weather Data, Desiccant Wheel Calculator, Ship Date Calculator, RPH/Time Calculator, Bypass CFM Calculator, Duct Diameter &amp; Friction Loss, Duct Diameter &amp; Velocity, Duct Velocity &amp; Friction Loss — re-upload via admin editor</figcaption></figure><p>Enter the Elevation, Temperature and Grains to get Dewpoint.</p><figure class="img-missing"><figcaption>&#128247; Image from Trainual: Psychrometric calculator interface showing input fields for Elevation (550), Volume (cubic inches), and Moisture (gr/lb = 29), with results displaying Volume, Temperature, Humidity, Wet Bulb, Dew Point (highlighted at -40.5), Humid. Ratio, Specific Vol., Air Density, Sat. Vapor Pressure — re-upload via admin editor</figcaption></figure><p>If &lt; -40F Td, select an ultra low dewpoint sensor. Example EE355 low dewpoint sensor.</p>', 71, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'engineering'
