INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Check Decibel Level', 'check-decibel-level', '<h2>Check Decibel Level</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF — "WAY TOO LOUD" (humorous illustration of noise level) — re-upload via admin editor</figcaption></figure><h3>Objective</h3><p>To accurately measure and document the decibel levels emitted by the unit at various points, ensuring compliance with sound level regulations and maintaining operational efficiency.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded video — "Checking Decibel Levels" (3 min, 2 min 31 sec at 1.2x) — re-upload via admin editor</figcaption></figure><h3>Procedure</h3><ol><li><strong>Preparation</strong><ul><li>Ensure the X-Tech sound level meter is fully charged and operational.</li><li>Turn on the sound level meter and verify that it is set to the appropriate mode for measuring decibels.</li></ul></li><li><strong>Unit Setup</strong><ul><li>Confirm that the unit is fully operational. This includes:<ul><li>Turning on the process motors.</li><li>Turning on the wheel motor.</li><li>Turning on the reactor motor.</li></ul></li></ul></li><li><strong>Measuring Decibel Levels</strong><ul><li>Front of the Unit<ul><li>Stand approximately 4 to 5 feet away from the front of the unit.</li><li>Allow the sound level meter to stabilize and take the reading.</li><li>Record the decibel level (e.g., 69 dB).</li></ul></li><li>Process Inlet<ul><li>Move to the process inlet of the unit.</li><li>Stand 4 to 5 feet away and allow the meter to settle.</li><li>Record the decibel level (e.g., 73.6 dB).</li></ul></li><li>Back of the Unit<ul><li>Position yourself at the back of the unit, maintaining a distance of 4 to 5 feet.</li><li>Allow the meter to stabilize and take the reading.</li><li>Record the decibel level (e.g., 78 dB).</li></ul></li><li>React Inlet<ul><li>Finally, move to the react inlet.</li><li>Stand 4 to 5 feet away, let the meter settle, and take the reading.</li><li>Record the decibel level (e.g., 72.2 dB).</li></ul></li></ul></li><li><strong>Documentation</strong><ul><li>Compile all recorded decibel levels into a designated log or report format.</li><li>Ensure that all readings are clearly labeled with the corresponding location and date of measurement.</li></ul></li></ol>', 13, TRUE, 5
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'testing-training'
ON CONFLICT (module_id, slug) DO NOTHING;
