-- ── Lessons: Shipping Training ──
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why Quality Cleaning Matters', 'why-quality-cleaning-matters', '<h2>Why Quality Cleaning Matters</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Why Quality Cleaning Matters intro video — re-upload via admin editor</figcaption></figure><p>Let''s dive into how to keep those Compact dehumidifiers, the stars of the show, sparkling clean. Making sure they''re in tip-top shape for our customers is super important to us.</p><p><strong>Compact Sizes:</strong></p><ul><li>75REC</li><li>150REC</li><li>300REC</li><li>600REC</li></ul><p>Plus, they''re versatile — good for <strong>both</strong> indoor and outdoor use.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: "I Love Its Versatility" product photo — re-upload via admin editor</figcaption></figure><p>Now, paying attention to the little things? That''s key, whether we''re talking production, cleaning, or getting these units shipped out.</p><p>Got any questions about all this? Just hit up the Shipping Manager. They''ve got the answers.</p>', 0, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview of Process', 'overview-of-process-cleaning', '<h2>Overview of Process</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Overview of cleaning process video — re-upload via admin editor</figcaption></figure><p>Click below to download the printable instruction manual for this process: <a href="Compact_Cleaning___Shipping_rev12.2024.pdf">Compact_Cleaning___Shipping_rev12.2024.pdf</a></p><h3>Steps in the Process</h3><ol><li>Remove Unit Front Cover</li><li>Vacuum Top &amp; Internal Compartments</li><li>Insert Process Filter</li><li>Reattach Front Cover</li><li>Insert React Filter</li><li>Place top lid before cleaning exterior</li><li>Clean Exterior</li><li>Apply &ldquo;Filter Access&rdquo; Sticker</li><li>Apply &ldquo;Process Outlet&rdquo; Sticker</li><li>Apply &ldquo;React Inlet&rdquo; Sticker</li><li>Apply &ldquo;Process Inlet&rdquo; Sticker</li><li>Apply &ldquo;React Outlet&rdquo; Sticker</li><li>Apply IAT Logo sticker</li><li>Apply &ldquo;Unit identification&rdquo; Sticker</li><li>Apply &ldquo;Data Plate&rdquo; Sticker</li><li>Apply necessary info to unit lid</li><li>Re-Install Lid</li><li>Apply &ldquo;Electrical Shock&rdquo; sticker</li><li>Place Unit on pallet</li></ol><h3>Materials &amp; Tools</h3><p><strong>Materials Needed:</strong></p><ol><li>3M Stainless steel cleaner spray (gloves recommended)</li><li>Cleaning rags</li><li>6 Bolts (#3385 / 5/16&times;3/4&rdquo;), 6 Lock washers (#119 / 5/16&times;18-8), 6 Flat washers (#3383 / 5/16&times;18-8), or Rubber outdoor unit washers</li><li>4 Pallet Screws (#1134 / #14 &times; 1-1/2&rdquo;) &amp; 4 Washers (#4510 / 5/16&rdquo;)<ul><li>Process in air filter<ul><li>10&rdquo; &times; 10&rdquo; &times; 1&rdquo; &mdash; 150REC, 300REC, &amp; 600REC</li><li>6&rdquo; &times; 6&rdquo; &times; 1&rdquo; &mdash; 75REC <strong>Only</strong></li></ul></li><li>React in air filter<ul><li>6&rdquo; &times; 6&rdquo; &times; 1&rdquo; &mdash; 75REC, 150REC, &amp; 300REC</li><li>10&rdquo; &times; 10&rdquo; &times; 1&rdquo; &mdash; 600REC <strong>Only</strong></li></ul></li></ul></li><li>Stickers:<ul><li>a. Process in &amp; out</li><li>b. React in &amp; out</li><li>c. Filter access (2)</li><li>d. Front IAT Logo</li><li>e. Data plate</li><li>f. Front identification label</li><li>g. Shock warning</li><li>h. Warranty</li></ul></li><li>Clear gorilla tape or 3M Double-sided tape</li><li>Blue stretch wrap on hand held dispenser</li><li>White compact pallet box (size varies based on the unit) &amp; IAT logo shipping tape for compact box</li><li>Adhesive laminated unit startup document, Adhesive laminated unit electrical drawing (both 8.5&rdquo; &times; 11&rdquo; documents)</li><li>IOM USB and clear USB case (There should be an identification label with the job# on the USB case)</li><li>Unit pallet (varies based on unit size)</li></ol><p><strong>Tools Needed:</strong></p><ol><li>#2 or #3 Phillips head &amp; drill (set to Torque level 11) or screwdriver</li><li>Impact drill (Hex drive adapter may be needed)</li><li>3/8-inch socket for Impact drill</li><li>Staple Gun with 18 Gauge 1/4&rdquo; crown staples</li><li>Shop vacuum with angled hose attachment</li><li>Razor blade</li><li>Smoothing Squeegee</li><li>Scissors</li></ol>', 1, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Removing Front Cover', 'removing-front-cover', '<h2>Removing Front Cover</h2><h3>Remove unit''s front face cover</h3><figure class="img-missing"><figcaption>📷 Image from Trainual: Nicolas Cage face-off GIF — re-upload via admin editor</figcaption></figure><p>Remove the screws holding the face on the front of the unit:</p><ul><li>600REC &mdash; 10 screws</li><li>150 &amp; 300REC &mdash; 8 screws</li><li>75REC &mdash; 6 screws</li></ul><p>Once removed, place screws together and lay the cover to the side <strong>with the front side facing upward.</strong></p><p>Inspect the rotor observation window to ensure there are no cracks.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Removing front cover photo — re-upload via admin editor</figcaption></figure>', 2, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Vacuum', 'vacuum', '<h2>Vacuum</h2><h3>Vacuum top of the unit and internal compartments</h3><figure class="img-missing"><figcaption>📷 Image from Trainual: Vacuuming internal compartments video clip — re-upload via admin editor</figcaption></figure><p>When vacuuming, gather all loose wire clippings, metal shavings, visible dirt, and any paper left in either section.</p><ul><li>You may have to lift the electrical wires to clean under them.</li><li>It is best to vacuum the top compartment from both the front and rear of the unit in case some particles are in hard-to-reach areas.</li></ul><figure class="img-missing"><figcaption>📷 Image from Trainual: Vacuuming top compartment wiring photo — re-upload via admin editor</figcaption></figure><blockquote>Check for and report any loose or disconnected wiring.</blockquote><p>Apply medium pressure when vacuuming the front compartments (interior floors and side walls), as particles may get stuck to the insulation.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Vacuuming front compartment photo — re-upload via admin editor</figcaption></figure><p>Lastly, vacuum under the rotor wheel and chain. Be sure to clean the front face cover as well.</p>', 3, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Insert Process Filter', 'insert-process-filter', '<h2>Insert Process Filter</h2><h3>Insert process inlet air filter</h3><p><strong>Filter Sizes:</strong></p><ul><li>5&rdquo; &times; 5&rdquo; &times; 1&rdquo; for 75REC</li><li>10&rdquo; &times; 10&rdquo; &times; 1&rdquo; for 150 &ndash; 600REC</li></ul><figure class="img-missing"><figcaption>📷 Image from Trainual: Inserting process filter photo — re-upload via admin editor</figcaption></figure><p>When facing the front of the unit, air travels from the left (process inlet) to right (process outlet).</p><p>The filter should be inserted on the left side of the unit in the slot behind the process inlet; ensure the wiring on the filter faces towards the inside of the unit.</p><blockquote><strong>The airflow arrow on the filter should be pointed towards the rotor wheel.</strong></blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Airflow diagram showing process inlet, react fan, heat source, filter, and rotating desiccant wheel — re-upload via admin editor</figcaption></figure>', 4, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Reattach Front Cover', 'reattach-front-cover', '<h2>Reattach Front Cover</h2><h3>Reattach front face cover</h3><p>Gather the screws and washers for the cover and reinsert them <strong>hand-tight first.</strong></p><ul><li>600REC &mdash; 10 screws/washers</li><li>150 &amp; 300REC &mdash; 8 screws/washers</li><li>75REC &mdash; 6 screws/washers</li></ul><blockquote>Drill torque should be set to Level 11 to avoid overtightening.</blockquote><p>Once all screws hold the cover to the unit, <em>follow the diagram below</em> to tighten each screw.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Numbered screw tightening pattern diagram — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Technician tightening front cover screws photo — re-upload via admin editor</figcaption></figure>', 5, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Insert React Filter', 'insert-react-filter', '<h2>Insert React Filter</h2><h3>Insert the react-in air filter</h3><p><strong>Filter Sizes:</strong></p><ul><li>6&rdquo; &times; 6&rdquo; &times; 1&rdquo; for 75 &ndash; 300REC</li><li>10&rdquo; &times; 10&rdquo; &times; 1&rdquo; for 600REC</li></ul><p>Gather screws, washers, and the react-inlet filter.</p><p>Insert filter into the access slot.</p><blockquote>If the filter access cover is already installed, remove all screws and the cover first.</blockquote><p><em>The wires in the filter should face toward the unit with airflow arrow pointed towards the rotor wheel.</em></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Inserting react-in filter photo — re-upload via admin editor</figcaption></figure><p>Once the filter is inserted, place the cover back over the slot and tighten the screws in an X pattern. <strong>Do NOT overtighten.</strong></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Filter cover screw tightening diagram — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Technician installing react filter cover photo — re-upload via admin editor</figcaption></figure>', 6, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Place Top Lid', 'place-top-lid', '<h2>Place Top Lid</h2><h3>Place lid on unit before cleaning the exterior</h3><p>Before spraying any cleaning solution on the unit, place the lid on it to prevent liquid from damaging electrical components.</p><blockquote>You DO NOT need to add the screws at this time.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Placing top lid on unit photo — re-upload via admin editor</figcaption></figure>', 7, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Clean Exterior', 'clean-exterior', '<h2>Clean Exterior</h2><h3>Clean exterior of the unit using 3M Stainless Steel Cleaner</h3><p><em>Clean one side at a time</em> making sure to clean under and around the inlets and outlets.</p><ol><li>Lightly spray the cleaning solution over the area.<figure class="img-missing"><figcaption>📷 Image from Trainual: Spraying cleaner on unit side photo — re-upload via admin editor</figcaption></figure></li><li>Use a white cloth to wipe off the solution.<figure class="img-missing"><figcaption>📷 Image from Trainual: Wiping down unit exterior with white cloth photo — re-upload via admin editor</figcaption></figure></li><li>Repeat these steps on all four sides.<figure class="img-missing"><figcaption>📷 Image from Trainual: Cleaning all sides of unit photo — re-upload via admin editor</figcaption></figure></li></ol>', 8, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"Filter Access" Sticker', 'filter-access-sticker', '<h2>&ldquo;Filter Access&rdquo; Sticker</h2><h3>Apply process inlet &ldquo;filter access&rdquo; sticker</h3><blockquote>A line is etched into the front cover to mark where the sticker will be placed.</blockquote><p>Align sticker with the mark and <strong>press down firmly</strong> to ensure it adheres securely and <strong>no air bubbles</strong> are present.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying filter access sticker to front cover photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Filter access sticker applied to unit photo — re-upload via admin editor</figcaption></figure>', 9, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"Process Outlet" Sticker', 'process-outlet-sticker', '<h2>&ldquo;Process Outlet&rdquo; Sticker</h2><h3>Apply &ldquo;process outlet&rdquo; sticker</h3><p>A line is etched into the metal over the outlet duct.</p><blockquote>Process outlet is located next to the air filter cover, on the right side of the unit.</blockquote><p>Align your sticker with the etched line and press down firmly to ensure it <strong>adheres securely</strong> and <strong>no air bubbles</strong> are present.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying process outlet sticker photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Process outlet sticker applied photo — re-upload via admin editor</figcaption></figure>', 10, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"React Inlet" Sticker', 'react-inlet-sticker', '<h2>&ldquo;React Inlet&rdquo; Sticker</h2><h3>Apply &ldquo;react inlet&rdquo; sticker</h3><p>A line is etched into the metal over the inlet duct.</p><blockquote>The react inlet duct is situated on the right side of the unit with the air filter slot on top.</blockquote><p>Align your sticker with the etched line and press down firmly to ensure it <strong>adheres securely</strong>, and <strong>no air bubbles</strong> are present.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying react inlet sticker photo — re-upload via admin editor</figcaption></figure>', 11, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
