ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"Process Inlet" Sticker', 'process-inlet-sticker', '<h2>&ldquo;Process Inlet&rdquo; Sticker</h2><h3>Apply &ldquo;process inlet&rdquo; sticker</h3><p>A line is etched into the metal over the inlet duct.</p><blockquote>The process inlet duct is located on the left side of the unit.</blockquote><p>Align &ldquo;process inlet&rdquo; sticker with the etched line and press down firmly to ensure it <strong>adheres securely</strong>, and <strong>no air bubbles</strong> showing.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying process inlet sticker photo — re-upload via admin editor</figcaption></figure>', 12, TRUE, 1
