INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"React Outlet" Sticker', 'react-outlet-sticker', '<h2>&ldquo;React Outlet&rdquo; Sticker</h2><h3>Apply &ldquo;react outlet&rdquo; sticker</h3><p>A line is etched into the metal over the outlet duct.</p><blockquote>The react outlet is on the left side of the unit next to the left of the mini helix.</blockquote><p>Align your sticker with the mark and press down firmly to <strong>ensure it adheres</strong> with <strong>no air bubbles</strong> present.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying react outlet sticker photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: React outlet sticker applied to unit photo — re-upload via admin editor</figcaption></figure>', 13, TRUE, 1
