INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'IAT Logo Sticker', 'iat-logo-sticker', '<h2>IAT Logo Sticker</h2><h3>Apply IAT Logo sticker to front of Compact</h3><p>When applying the IAT logo sticker, align it above the observation window then press starting <strong>from the bottom</strong> working upward.</p><p><em>Use the flat squeegee to remove air bubbles.</em></p><p>Press firmly on all areas to ensure sticker adheres securely.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Applying IAT logo sticker with squeegee photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: IAT logo sticker applied to unit front photo — re-upload via admin editor</figcaption></figure>', 14, TRUE, 2
