ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Unit Identification Sticker', 'unit-identification-sticker', '<h2>Unit Identification Sticker</h2><h3>Apply &ldquo;Unit Identification&rdquo; sticker to front left corner of unit</h3><p>Align your identification sticker with the etched marking on the front left of the unit, then firmly press down for secure placement.</p><blockquote>This sticker includes the unit serial number, model number, and company name.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit identification sticker with serial number, model, and company name photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit identification sticker applied to front left corner photo — re-upload via admin editor</figcaption></figure>', 15, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Data Plate Sticker', 'data-plate-sticker', '<h2>Data Plate Sticker</h2><h3>Apply the &ldquo;Data Plate&rdquo; sticker inside the unit</h3><p>This sticker should be placed <strong>inside the unit</strong>, typically to the left or right of the mini helix, depending on the spacing of the inner walls.</p><p>Aligning &ldquo;data plate&rdquo; with the electrical warning sticker over the mini helix.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Data plate sticker placement inside unit near mini helix photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Data plate sticker showing job info, unit model, motor data photo — re-upload via admin editor</figcaption></figure>', 16, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Apply Unit Lid Stickers', 'apply-unit-lid-stickers', '<h2>Apply Unit Lid Stickers</h2><h3>Apply USB case, electrical drawings, warranty sticker, and start-up procedure to lid</h3><blockquote>All compacts, except the 600REC, require four items on the unit lid:</blockquote><ol><li>QR code sticker</li><li>Case containing an IOM USB with unit-specific paperwork</li><li>Electrical drawing</li><li>Startup document on laminated peel-and-stick paper</li></ol><p><em>provided by the front desk office administrator</em></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit lid with USB case and laminated documents applied photo — re-upload via admin editor</figcaption></figure><p>The two 8.5&rdquo; &times; 11&rdquo; laminated documents should be placed side by side, with the other two items below each page.</p><p>Cut two 3&rdquo; pieces of double-sided tape and attach them to the top and bottom of the clear USB case to adhere it to the top lid.</p><blockquote>Due to limited space, the 75REC requires closer placement of items to accommodate everything.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: 75REC lid layout with compressed item placement photo — re-upload via admin editor</figcaption></figure><blockquote>Once complete, inform the marketing team that the unit is ready for documentation.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: "Ready for documentation" notification GIF — re-upload via admin editor</figcaption></figure>', 17, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Re-Install Lid', 're-install-lid', '<h2>Re-Install Lid</h2><h3>Re-install top lid cover bolts</h3><p><strong>Gather items needed to secure lid:</strong></p><ul><li>Bolts (#3385 / 5/16&times;3/4&rdquo;)</li><li>Lock washers (#119 / 5/16&times;18-8)</li><li>Flat washers (#3383 / 5/16&times;18-8)</li></ul><blockquote>The lock washer goes onto the bolt, followed by the flat washer.</blockquote><blockquote>Note: Outdoor units will use flat rubber grommet washers.</blockquote><p>Place bolts in each hole and hand-tighten three turns to ensure the lid is oriented correctly.</p><blockquote>If the holes do not align, rotate the lid 180&deg;.</blockquote><p>Once the lid holes align with rivet nuts, use your drill on <strong>torque 11</strong> to tighten bolts down.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Tightening lid bolts with impact drill photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Completed lid installation on unit photo — re-upload via admin editor</figcaption></figure>', 18, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, '"Electrical Shock" Sticker', 'electrical-shock-sticker', '<h2>&ldquo;Electrical Shock&rdquo; Sticker</h2><h3>Apply &ldquo;electrical shock&rdquo; warning sticker to front left corner of top lid</h3><blockquote>A line is etched into the metal to serve as a guide.</blockquote><p>The &ldquo;electrical shock warning&rdquo; sticker will be placed on the lid, on the <strong>bottom left corner</strong> toward the front of the unit.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Electrical shock warning sticker (WARNING / AVERTISSEMENT bilingual label) — re-upload via admin editor</figcaption></figure><p>Align your sticker with the mark and press down to ensure the sticker <strong>adheres securely.</strong></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Electrical shock sticker applied to lid corner photo — re-upload via admin editor</figcaption></figure>', 19, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Place Unit on Pallet', 'place-unit-on-pallet-cleaning', '<h2>Place Unit on Pallet</h2><h3>Place unit on the pallet</h3><p><strong>Using a forklift</strong>, raise the empty pallet to the same height as the table the unit is sitting on.</p><p>Slide the compact unit off the table onto the 2&rdquo; &times; 4&rdquo; boards in the center of the pallet.</p><blockquote>Make sure the unit is as centered as possible, as the white compact box will need to go over the unit and be stapled to the 2&rdquo; &times; 4&rdquo; boards towards the outer edge of the pallet.</blockquote><blockquote>Double-check to ensure none of the inlets or outlets are hanging off the edge.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Unit centered on pallet photo — re-upload via admin editor</figcaption></figure><p>Take your four pallet screws and washers and place the washer over each screw. Use your impact drill with a 3/8&rdquo; socket to drive each screw into the holes at the bottom of each corner of the unit. These screws will anchor the unit to the pallet.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Pallet screws anchoring unit to pallet boards photo — re-upload via admin editor</figcaption></figure>', 20, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Ready for Shipping!', 'ready-for-shipping-cleaning', '<h2>Ready for Shipping!</h2><h3>Great job!</h3><p>The Compact Unit is now clean and ready to be packaged for shipping.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: "Great Job" celebration GIF — re-upload via admin editor</figcaption></figure>', 21, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Why Quality Shipping Matters', 'why-quality-shipping-matters', '<h2>Why Quality Shipping Matters</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Why Quality Shipping Matters intro video — re-upload via admin editor</figcaption></figure><p>So, we''re at the final stretch &mdash; getting our top-notch desiccant dehumidifiers into the hands of our customers. It''s all about the <strong>wrap</strong>, the <strong>label</strong>, and the <strong>box</strong>.</p><blockquote>These aren''t just steps; they''re our way of making sure our units get to our customer in just as perfect as they left our facility.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Ace Ventura delivery scene GIF — re-upload via admin editor</figcaption></figure><p>Plus, getting it right the first time means we dodge the hassle and expense of dealing with returns or damage.</p><p>This course will guide you to pack like a pro and ensure our dehumidifiers arrive in tip-top shape.</p>', 22, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Overview', 'overview-shipping', '<h2>Overview</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Shipping process overview video — re-upload via admin editor</figcaption></figure><p>In case you missed it in the last training course, click below to download a printable version of the Compact Cleaning &amp; Shipping Instruction Manual: <a href="Compact_Cleaning___Shipping_rev12.2024.pdf">Compact_Cleaning___Shipping_rev12.2024.pdf</a></p><h3>Steps</h3><ol><li>Place Unit on pallet</li><li>Blue Wrap the unit</li><li>Place White Box over unit</li><li>Affix Packaging Slip &amp; Shipping Label</li><li>Affix box to pallet</li><li>Unit is ready for shipping!</li></ol>', 23, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Place Unit on Pallet', 'place-unit-on-pallet-shipping', '<h2>Place Unit on Pallet</h2><h3>Place unit on the pallet</h3><figure class="img-missing"><figcaption>📷 Image from Trainual: Placing unit on pallet video — re-upload via admin editor</figcaption></figure><p><strong>Using a forklift</strong>, raise the empty pallet to the same height as the table the unit is sitting on.</p><p>Slide the compact unit off the table onto the 2&rdquo; &times; 4&rdquo; boards in the center of the pallet.</p><blockquote>Make sure the unit is as centered as possible, as the white compact shipping box will need to go over the unit and be stapled to the 2&rdquo; &times; 4&rdquo; boards towards the outer edge of the pallet.</blockquote><blockquote>Double-check to ensure none of the inlets or outlets are hanging off the edge.</blockquote><figure class="img-missing"><figcaption>📷 Image from Trainual: Centered unit on pallet photo — re-upload via admin editor</figcaption></figure><p>Take your 4 pallet screws and washers and place the washer over each screw. Using your impact drill with a 3/8&rdquo; socket, drive each screw into the holes at the bottom of each corner of the unit.</p><p><em>These screws will anchor the unit to the pallet.</em></p><figure class="img-missing"><figcaption>📷 Image from Trainual: Impact drill driving pallet screws into corners photo — re-upload via admin editor</figcaption></figure>', 24, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Blue Wrap', 'blue-wrap', '<h2>Blue Wrap</h2><h3>Cover the unit with Blue stretch wrap</h3><figure class="img-missing"><figcaption>📷 Image from Trainual: Blue wrap team photo — re-upload via admin editor</figcaption></figure><ol><li>Take the blue wrap and tie the end to the react outlet damper handle. Do not over-tighten.<figure class="img-missing"><figcaption>📷 Image from Trainual: Tying blue wrap to react outlet damper handle photo — re-upload via admin editor</figcaption></figure></li><li>Once your knot is anchored to the damper, <strong>go over and around</strong> the unit with the blue wrap 5&ndash;8 times or until the top and sides are completely covered.<figure class="img-missing"><figcaption>📷 Image from Trainual: Unit wrapped in blue stretch wrap photo — re-upload via admin editor</figcaption></figure></li><li>Once complete, tear the wrapping away from the spool. Use your hand to go over the blue wrap and flatten all loose pieces.<figure class="img-missing"><figcaption>📷 Image from Trainual: Flattening blue wrap on unit photo — re-upload via admin editor</figcaption></figure></li></ol>', 25, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'White Box', 'white-box', '<h2>White Box</h2><h3>Preparing the white compact box cover</h3><blockquote>Select the white box based on the unit size.</blockquote><p>Unfold it and set it upright with the top flat.</p><p>Use the <em>IAT logo shipping tape</em> to cover all gaps, edges, and sides as shown.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: White compact box with IAT logo shipping tape applied photo — re-upload via admin editor</figcaption></figure><p>Next, on opposite sides of the top of the box, apply your &lsquo;Fragile&rsquo; and &lsquo;Do NOT double stack&rsquo; labels.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Fragile / Handle with Care / High Claim Value green label photo — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: Do Not Double Stack orange label photo — re-upload via admin editor</figcaption></figure><blockquote>Place the box over the compact.</blockquote>', 26, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Packaging Slip &amp; Unit Label', 'packaging-slip-and-unit-label', '<h2>Packaging Slip &amp; Unit Label</h2><h3>Place the packaging slip and shipping label on the box</h3><p>Take the packing slip and place it on one side at the top of the box.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Packing slip placed on top of white box photo — re-upload via admin editor</figcaption></figure><p>Affix the shipping label adjacent to the packing slip.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Packing slip and shipping label side by side on box top photo — re-upload via admin editor</figcaption></figure>', 27, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Affix Box', 'affix-box', '<h2>Affix Box</h2><h3>Staple box to the pallet and label box</h3><p>Use your <strong>staple gun</strong> to nail the bottom of the box to the outer 2&rdquo; &times; 4&rdquo; wood pieces on the pallet.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Staple gun nailing box to pallet wood photo — re-upload via admin editor</figcaption></figure><blockquote>You should only use 4&ndash;6 staples per side depending on the size of the box.</blockquote><p>Lastly, write the unit number on the side of the box. This helps everyone keep track of the unit.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: White box stapled to pallet with unit number written on side photo — re-upload via admin editor</figcaption></figure>', 28, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'technical-training' AND m.slug = 'shipping-training'
ON CONFLICT (module_id, slug) DO NOTHING;
