SELECT m.id, 'IDP Overview', 'idp-overview', '<h2>IDP Overview</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: IDP Series Overview video thumbnail (Trainual-hosted video, 1 min 24 sec) — re-upload via admin editor</figcaption></figure><h3>Key Points:</h3><ol><li>IDP standard for "Integrated Dehumidification Package"</li><li>Turnkey HVAC system</li><li>Customized to customer''s needs</li><li>Many available options (including but not limited to):<ol><li>Pre-cooling</li><li>Post-cooling</li><li>Pre-heating</li><li>Post-heating</li><li>Specialty filtration</li><li>Bypass Dampers</li><li>Specialty Humidity Control (including humidification)</li></ol></li></ol>', 3, TRUE, 4
