INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'What is the Desiccant Wheel Calculator', 'what-is-the-desiccant-wheel-calculator', '<h2>What is the Desiccant Wheel Calculator</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: YouTube video thumbnail — IAT Psychrometric App intro video on YouTube — re-upload via admin editor</figcaption></figure><p>The Desiccant Wheel Calculator is a tool built into the DryWare psychrometric app (also called the Calculator App) by Innovative Air Technologies. It guides you through the desiccant wheel selection process by calculating the optimal drying moisture content and RPH (Rotation Per Hour) based on your specific inlet conditions.</p>', 0, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Where Can I Find the Calculator', 'where-can-i-find-the-calculator', '<h2>Where Can I Find the Calculator</h2><p>You can find a link to our Calculator App on the top menu on our <a href="http://www.dehumidifiers.com">website</a>.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Screenshot of dehumidifiers.com homepage with the Calculator App menu item circled in red — re-upload via admin editor</figcaption></figure><p>Or you can click the link <strong>HERE</strong>.</p>', 1, TRUE, 1
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
