SELECT m.id, 'How to Download the Calculator', 'how-to-download-the-calculator', '<h2>How to Download the Calculator</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: YouTube video thumbnail — FREE Psychrometric Calculator app download tutorial showing phone screen with app store — re-upload via admin editor</figcaption></figure>', 2, TRUE, 2
