INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Calculator Inputs Overview', 'calculator-inputs-overview', '<h2>Calculator Inputs Overview</h2><p>The video below will guide you through using the desiccant wheel calculator to determine the appropriate settings for your desiccant wheel based on specific inputs.</p><p>👇Check it out!👇</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded Loom/screen-recording video thumbnail titled “Calculator Inputs Overview” showing the calculator interface — re-upload via admin editor</figcaption></figure><h3>Key Steps</h3><ol><li>Go to <a href="http://www.dehumidifiers.com">www.dehumidifiers.com</a> &amp; click on the calculator app.</li><li>Select the <strong>Desiccant Wheel Calculator</strong>.</li><li>Input the CFM for your process.</li><li>Input the CFM for your react.</li><li>Input the entering temperature.</li><li>Input the entering grains on the process.</li><li>Input the entering grains on your react.</li><li>Input the elevation of your current/proposed elevation for the desiccant wheel.</li></ol><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF or short video clip of a woman with text overlay “Just a reminder” — re-upload via admin editor</figcaption></figure><h3>Check out these reminders</h3><blockquote><p>👇 Ensure that you input accurate values for CFM, temperature, grains, and elevation to get precise calculations.</p><p>👇 Double-check all inputs before proceeding with the calculation to avoid errors in the results.</p></blockquote><h3>Tips for Efficiency</h3><ul><li>Have all the necessary information ready before starting to use the calculator.</li><li>Familiarize yourself with the calculator interface to navigate through the inputs quickly.</li><li>Review the calculated results to ensure they align with your requirements before implementing any changes based on the recommendations.</li></ul>', 3, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Desiccant Wheel Calculator', 'desiccant-wheel-calculator', '<h2>Desiccant Wheel Calculator</h2><p>In this video you will learn how to run the desiccant wheel calculator to determine the optimal drying moisture content based on specified inlet conditions.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Desiccant Wheel Calculator Tutorial” showing the calculator interface — re-upload via admin editor</figcaption></figure><p>OK, you all know we love a good process...</p><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with text overlay “ADDICTED TO THE PROCESS!” — re-upload via admin editor</figcaption></figure><p>so check out the steps below ↓</p><h3>Key Steps</h3><ol><li>Fill out the required information including CFM, inlet temperature, and humidity levels.</li><li>Enter the desiccant wheel size.</li><li>Check the “optimize” button to allow the calculator to optimize the speed of the desiccant wheel based on the inlet conditions.</li><li>Click on the “calculate” button.</li><li>Review the calculated results which will include the optimized RPH (Rotation Per Hour) for the best temperature and humidity performance.</li><li>Note the outlet conditions on the process and reactivation outlet, including temperature, humidity, BTUs per pound, energy dew points, delta, and pressure drop.</li><li>Make any necessary adjustments based on the calculated results.</li></ol><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF or meme image with text “just FYI.” (man in suit gesturing) — re-upload via admin editor</figcaption></figure><blockquote><p><strong>Be cautious when making manual changes to the optimized settings, as it may affect the overall performance of the desiccant wheel.</strong></p></blockquote><h3>Tips</h3><ul><li>Leave the “optimize” button checked for the most accurate and optimal results.</li><li>Review the calculated results thoroughly to understand the performance metrics provided.</li><li>Experiment with different input values to understand the impact on the desiccant wheel performance.</li></ul>', 4, TRUE, 4
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Adding Temperature', 'adding-temperature', '<h2>Adding Temperature</h2><p>Let’s talk about inputting temperature and humidity data.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Photo of an outdoor thermometer mounted on a brick wall — re-upload via admin editor</figcaption></figure><h3>Key Steps</h3><ol><li>Enter the temperature and humidity data by typing in the values.</li><li>Alternatively, click on the process calculator icon and input the temperature and relative humidity values.<ul><li>Be sure to work with grains per pound for accurate humidity measurements.</li></ul></li><li>Click “use results” to populate the moisture grains per pound field.</li><li>Repeat the same process for the reactivation temperature.<ul><li>Typically set at 285 degrees.</li></ul></li><li>If adjusting the reactivation temperature, consider the external conditions.</li><li>Convert the wet bulb value to grains per pound and input it into the system.</li><li>Click “use results” to save the data.</li><li>Input the elevation data, considering the specific location of the dehumidifier.</li></ol><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Adding Temperature” showing the calculator interface — re-upload via admin editor</figcaption></figure><blockquote><p><strong>Note:</strong> Be cautious when adjusting the reactivation temperature as it can impact system efficiency.</p></blockquote>', 5, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Understanding the Air Mixing Tab', 'understanding-the-air-mixing-tab', '<h2>Understanding the Air Mixing Tab</h2><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Understanding the Air Mixing Tab” showing the air mixing interface — re-upload via admin editor</figcaption></figure><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with text overlay “WHAT AM I EVEN DOING” (child at desk) — re-upload via admin editor</figcaption></figure><h3>Key Steps</h3><ol><li>Go to <a href="http://www.dehumidifiers.com">www.dehumidifiers.com</a> and access the calculator app.</li><li>Click on the Air Mixing tab.</li><li>Identify Airstream A and Airstream B (e.g., outside air and return air).</li><li>Input the temperature, humidity, and CFM for each Airstream.</li><li>The app will automatically calculate the mixed air condition.<ul><li>Note the percentage of each Airstream in the mix.</li><li>Use the slider to experiment with different air mixing ratios.</li></ul></li></ol><h3>Tips for Efficiency</h3><ul><li>Label Airstream A and Airstream B clearly for easy identification.</li><li>Experiment with different mixing ratios to understand the effects on the mixed air condition.</li></ul>', 6, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Airflow CFM', 'airflow-cfm', '<h2>Airflow CFM</h2><p>Use the Airflow CFM to determine the appropriate desiccant wheel size based on the process airflow (CFM) for effective dehumidification.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Airflow CFM” showing the calculator interface — re-upload via admin editor</figcaption></figure><h3>Key Steps</h3><ol><li>Start by determining the process airflow in CFM.</li><li>Input the CFM value into the calculator.<ul><li>The calculator will automatically calculate a three to one ratio for the desiccant wheel size.</li><li>If needed, you can manually modify the ratio to adjust the CFM value.</li><li>Velocity is automatically calculated based on the cross-section of the desiccant wheel diameter.</li><li>Square footage times velocity equals CFM for calculation.</li></ul></li><li>Refer to the CFM ranges provided in the tool to select the appropriate desiccant wheel size.</li></ol><figure class="img-missing"><figcaption>📷 Image from Trainual: GIF with text overlay “WELL, MELODY, AS YOU KNOW, I’M NEW HERE.” (two women outdoors) — re-upload via admin editor</figcaption></figure><blockquote><p><strong>Double check:</strong> Verify the selected desiccant wheel size aligns with the CFM range for optimal performance.</p></blockquote>', 7, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Weather Data', 'weather-data', '<h2>Weather Data</h2><p>Utilize the Weather Data App to access ASHRAE data for specific cities, providing heating, dehumidification, and cooling percentages for accurate calculations.</p><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Weather Data App Overview” showing the app interface — re-upload via admin editor</figcaption></figure><h3>Key Steps</h3><ol><li>Locate the Weather Data App — it’s the second tab down — and click on the Weather Data App to open it.</li><li>Enter the desired city to access the nearest ASHRAE weather station data.</li><li>Review the heating, dehumidification, and cooling percentages provided by the ASHRAE data for the selected city.</li><li>Utilize the data to make informed decisions based on the heating, dehumidification, and cooling percentages for the location.</li></ol><blockquote><p><strong>NOTE: Note that the app currently covers Canada and the United States only.</strong></p></blockquote>', 8, TRUE, 3
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
INSERT INTO learn_lessons (module_id, title, slug, content, display_order, is_published, estimated_minutes)
SELECT m.id, 'Ship Date Calculator', 'ship-date-calculator', '<h2>Ship Date Calculator</h2><p>Use the ship date calculator to determine estimated ship dates for orders.</p><h3>Key Steps</h3><ol><li>Go to <a href="http://dehumidifiers.com">dehumidifiers.com</a> and access the calculator app.</li><li>Click on the fourth large button down labeled “Ship Date Calculator.”</li><li>Enter the start date and the number of weeks required for the order.</li><li>Click on the “Calculate” button to determine the estimated ship date.<ul><li>Consider the current lead time (e.g., 22 to 24 weeks) and add any additional time for submittals.</li></ul></li><li>Review the estimated ship date provided by the calculator.</li></ol><figure class="img-missing"><figcaption>📷 Image from Trainual: Embedded screen-recording video thumbnail titled “Ship Date Calculator Tutorial” showing the calculator interface — re-upload via admin editor</figcaption></figure>', 9, TRUE, 2
FROM learn_modules m JOIN learn_categories c ON c.id = m.category_id
WHERE c.slug = 'products-tools' AND m.slug = 'using-dryware'
ON CONFLICT (module_id, slug) DO NOTHING;
